/**
 * Parse a simple CSV string into an array of objects.
 * Handles quoted fields and maps common column names to ProductFormData fields.
 */
function parseCsvToProducts(csvContent: string): Record<string, unknown>[] {
  const lines = csvContent.split(/\r?\n/).filter((l) => l.trim())
  if (lines.length < 2) return []

  const headers = lines[0].split(',').map((h) => h.trim().toLowerCase().replace(/['"]/g, ''))
  const rows: Record<string, unknown>[] = []

  for (let i = 1; i < lines.length; i++) {
    const values = lines[i].split(',').map((v) => v.trim().replace(/^["']|["']$/g, ''))
    const row: Record<string, unknown> = {}
    headers.forEach((h, idx) => {
      row[h] = values[idx] || ''
    })

    // Map CSV columns to ProductFormData fields
    rows.push({
      name: row['name'] || row['product_name'] || row['product name'] || '',
      shortName: row['short_name'] || row['short name'] || null,
      barcode: row['barcode'] || null,
      hsnCode: row['hsn_code'] || row['hsn code'] || row['hsn'] || '',
      costPrice:
        parseFloat(
          String(
            row['cost_price'] ||
              row['cost price'] ||
              row['purchase_price'] ||
              row['purchase price'] ||
              '0'
          )
        ) || 0,
      sellingPrice:
        parseFloat(
          String(row['selling_price'] || row['selling price'] || row['price'] || row['mrp'] || '0')
        ) || 0,
      wholesalePrice:
        parseFloat(String(row['wholesale_price'] || row['wholesale price'] || '0')) || null,
      gstRate: parseFloat(String(row['gst_rate'] || row['gst rate'] || row['gst'] || '5')) || 5,
      stock:
        parseFloat(
          String(
            row['stock'] ||
              row['opening_stock'] ||
              row['opening stock'] ||
              row['current_stock'] ||
              '0'
          )
        ) || 0,
      lowStockThreshold:
        parseFloat(String(row['low_stock'] || row['low stock'] || row['low_stock_alert'] || '0')) ||
        null,
      color: row['color'] || null,
      size: row['size'] || null,
      material: row['material'] || null,
      description: row['notes'] || row['description'] || null,
      isActive: true
    })
  }
  return rows
}

export function registerProductIpc(): void {
  safeHandle('products:search', (_event, term) => {
    return productRepo.search(validate(searchTermSchema, term))
  })

  safeHandle('products:getAll', (_event, filters) => {
    return productRepo.getAll(validate(productFiltersSchema, filters))
  })

  safeHandle('products:getById', (_event, id) => {
    return productRepo.getById(validate(idSchema, id))
  })

  safeHandle('products:getByBarcode', (_event, barcode) => {
    return productRepo.getByBarcode(validate(z.string().min(1).max(50), barcode))
  })

  safeHandle('products:create', (_event, data) => {
    const validated = validate(productFormSchema, data)
    const result = productRepo.create(validated as Parameters<typeof productRepo.create>[0])
    log.info(`Product created: ${result.sku} - ${result.name}`)
    writeAuditLog({
      action: 'create',
      entityType: 'product',
      entityId: result.id,
      newValue: { sku: result.sku, name: result.name }
    })
    return result
  })

  safeHandle('products:update', (_event, id, data) => {
    const validId = validate(idSchema, id)
    const validated = validate(productFormSchema, data)
    const result = productRepo.update(
      validId,
      validated as Parameters<typeof productRepo.update>[1]
    )
    log.info(`Product updated: ${result.sku} - ${result.name}`)
    writeAuditLog({
      action: 'update',
      entityType: 'product',
      entityId: validId,
      newValue: { sku: result.sku, name: result.name }
    })
    return result
  })

  safeHandle('products:delete', (_event, id) => {
    const validId = validate(idSchema, id)
    writeAuditLog({ action: 'delete', entityType: 'product', entityId: validId })
    productRepo.delete(validId)
    log.info(`Product deleted: ${validId}`)
    return true
  })

  safeHandle('products:import', (_event, input) => {
    try {
      let rows: Record<string, unknown>[]

      if (Array.isArray(input) && input.length > 0 && typeof input[0] === 'string') {
        // Input is file paths from dialog ΓÇö read and parse the CSV file
        const filePath = input[0] as string
        const csvContent = readFileSync(filePath, 'utf-8')
        rows = parseCsvToProducts(csvContent)
      } else if (Array.isArray(input)) {
        // Input is already parsed product data
        rows = input as Record<string, unknown>[]
      } else {
        return { total: 0, imported: 0, skipped: 0, errors: ['Invalid import data'] }
      }

      const result = productRepo.bulkImport(rows as any)
      log.info(`Product import: ${result.imported} imported, ${result.skipped} skipped`)
      return result
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err)
      log.error('Product import failed:', msg)
      return { total: 0, imported: 0, skipped: 0, errors: [msg] }
    }
  })

  safeHandle('products:getLowStock', () => {
    return productRepo.getLowStock()
  })

  safeHandle('products:getOutOfStock', () => {
    return productRepo.getOutOfStock()
  })

  safeHandle('products:getStockValuation', () => {
    return productRepo.getStockValuation()
  })

  safeHandle('products:adjustStock', (_event, productId, quantity, type, notes?) => {
    const validId = validate(idSchema, productId)
    const validQty = validate(z.number().int(), quantity)
    const validType = validate(stockAdjustTypeSchema, type)
    const validNotes = notes ? validate(z.string().max(500), notes) : undefined
    const result = productRepo.adjustStock(validId, validQty, validType, validNotes)
    log.info(`Stock adjusted: Product ${validId}, ${validType} ${validQty}`)
    writeAuditLog({
      action: 'adjust_stock',
      entityType: 'product',
      entityId: validId,
      newValue: { type: validType, qty: validQty }
    })
    return result
  })

  safeHandle('products:getStockLedger', (_event, productId, limit?) => {
    return productRepo.getStockLedger(validate(idSchema, productId), validate(limitSchema, limit))
  })

  safeHandle('products:getPriceHistory', (_event, productId, limit?) => {
    return productRepo.getPriceHistory(validate(idSchema, productId), validate(limitSchema, limit))
  })

  safeHandle('products:bulkStockUpdate', (_event, items) => {
    const validated = validate(z.array(bulkStockItemSchema).min(1), items)
    const result = productRepo.bulkStockUpdate(validated)
    log.info(`Bulk stock update: ${result.imported} updated, ${result.skipped} skipped`)
    return result
  })

  // Categories
  safeHandle('categories:getAll', () => {
    return categoryRepo.getAll()
  })

  safeHandle('categories:create', (_event, name, parentId?) => {
    const validName = validate(z.string().min(1).max(100), name)
    const validParentId = parentId ? validate(idSchema, parentId) : undefined
    const result = categoryRepo.create(validName, validParentId)
    writeAuditLog({
      action: 'create',
      entityType: 'category',
      entityId: result.id,
      newValue: { name: validName }
    })
    return result
  })

  safeHandle('categories:update', (_event, id, name) => {
    const validId = validate(idSchema, id)
    const validName = validate(z.string().min(1).max(100), name)
    const result = categoryRepo.update(validId, validName)
    writeAuditLog({
      action: 'update',
      entityType: 'category',
      entityId: validId,
      newValue: { name: validName }
    })
    return result
  })

  safeHandle('categories:delete', (_event, id) => {
    const validId = validate(idSchema, id)
    writeAuditLog({ action: 'delete', entityType: 'category', entityId: validId })
    categoryRepo.delete(validId)
    return true
  })
}

// ============================================================================
// KPT Billing - Cloud Backup Service (Google Drive)
// Uses Google Drive REST API v3 with OAuth2 for desktop app
// ============================================================================
import { BrowserWindow, app } from 'electron'
import { existsSync, readFileSync, writeFileSync, statSync } from 'fs'
import { join, basename } from 'path'
import log from 'electron-log'
import { getBackupDir } from '../database/connection'
import { backupService } from './backup.service'

// Google OAuth2 Configuration
// Users must create their own OAuth credentials at https://console.cloud.google.com
const SCOPES = 'https://www.googleapis.com/auth/drive.file'
const REDIRECT_URI = 'http://localhost'

interface TokenData {
  access_token: string
  refresh_token: string
  token_type: string
  expires_in: number
  expiry_date: number
  scope: string
}

interface CloudConfig {
  clientId: string
  clientSecret: string
}

function getTokenPath(): string {
  return join(app.getPath('userData'), 'cloud_token.json')
}

function getConfigPath(): string {
  return join(app.getPath('userData'), 'cloud_config.json')
}

export class CloudBackupService {
  private token: TokenData | null = null
  private config: CloudConfig | null = null

  constructor() {
    this.loadToken()
    this.loadConfig()
  }

  private loadToken(): void {
    const tokenPath = getTokenPath()
    if (existsSync(tokenPath)) {
      try {
        this.token = JSON.parse(readFileSync(tokenPath, 'utf-8'))
      } catch {
        this.token = null
      }
    }
  }

  private saveToken(token: TokenData): void {
    this.token = token
    writeFileSync(getTokenPath(), JSON.stringify(token, null, 2))
  }

  private loadConfig(): void {
    const configPath = getConfigPath()
    if (existsSync(configPath)) {
      try {
        this.config = JSON.parse(readFileSync(configPath, 'utf-8'))
      } catch {
        this.config = null
      }
    }
  }

  saveConfig(clientId: string, clientSecret: string): void {
    this.config = { clientId, clientSecret }
    writeFileSync(getConfigPath(), JSON.stringify(this.config, null, 2))
  }

  getConfig(): CloudConfig | null {
    return this.config
  }

  isConfigured(): boolean {
    return !!(this.config?.clientId && this.config?.clientSecret)
  }

  isAuthenticated(): boolean {
    return !!(this.token?.access_token && this.isConfigured())
  }

  /**
   * Start OAuth2 flow in a popup window
   */
  async authenticate(): Promise<boolean> {
    if (!this.config) {
      throw new Error('Google Drive not configured. Please set Client ID and Client Secret first.')
    }

    const authUrl =
      `https://accounts.google.com/o/oauth2/v2/auth?` +
      `client_id=${encodeURIComponent(this.config.clientId)}` +
      `&redirect_uri=${encodeURIComponent(REDIRECT_URI)}` +
      `&response_type=code` +
      `&scope=${encodeURIComponent(SCOPES)}` +
      `&access_type=offline` +
      `&prompt=consent`

    return new Promise((resolve, reject) => {
      const authWindow = new BrowserWindow({
        width: 500,
        height: 700,
        show: true,
        title: 'Sign in to Google Drive',
        webPreferences: {
          nodeIntegration: false,
          contextIsolation: true
        }
      })

      authWindow.loadURL(authUrl)

      authWindow.webContents.on('will-redirect', async (_event, url) => {
        try {
          const parsed = new URL(url)
          const code = parsed.searchParams.get('code')
          const error = parsed.searchParams.get('error')

          if (error) {
            authWindow.destroy()
            reject(new Error(`Auth error: ${error}`))
            return
          }

          if (code) {
            authWindow.destroy()
            await this.exchangeCode(code)
            resolve(true)
          }
        } catch (err) {
          // Not a redirect we care about
        }
      })

      // Also handle navigation events
      authWindow.webContents.on('will-navigate', async (_event, url) => {
        try {
          if (url.startsWith(REDIRECT_URI)) {
            const parsed = new URL(url)
            const code = parsed.searchParams.get('code')
            if (code) {
              authWindow.destroy()
              await this.exchangeCode(code)
              resolve(true)
            }
          }
        } catch {
          // ignore
        }
      })

      authWindow.on('closed', () => {
        resolve(false)
      })
    })
  }

  private async exchangeCode(code: string): Promise<void> {
    if (!this.config) throw new Error('Not configured')

    const body = new URLSearchParams({
      code,
      client_id: this.config.clientId,
      client_secret: this.config.clientSecret,
      redirect_uri: REDIRECT_URI,
      grant_type: 'authorization_code'
    })

    const response = await this.httpPost(
      'https://oauth2.googleapis.com/token',
      body.toString(),
      'application/x-www-form-urlencoded'
    )

    const data = JSON.parse(response)
    if (data.error) {
      throw new Error(data.error_description || data.error)
    }

    this.saveToken({
      ...data,
      expiry_date: Date.now() + data.expires_in * 1000
    })
  }

  private async refreshAccessToken(): Promise<void> {
    if (!this.config || !this.token?.refresh_token) {
      throw new Error('No refresh token available. Please re-authenticate.')
    }

    const body = new URLSearchParams({
      refresh_token: this.token.refresh_token,
      client_id: this.config.clientId,
      client_secret: this.config.clientSecret,
      grant_type: 'refresh_token'
    })

    const response = await this.httpPost(
      'https://oauth2.googleapis.com/token',
      body.toString(),
      'application/x-www-form-urlencoded'
    )

    const data = JSON.parse(response)
    if (data.error) {
      throw new Error(data.error_description || data.error)
    }

    this.saveToken({
      ...this.token,
      access_token: data.access_token,
      expires_in: data.expires_in,
      expiry_date: Date.now() + data.expires_in * 1000
    })
  }

  private async getAccessToken(): Promise<string> {
    if (!this.token?.access_token) throw new Error('Not authenticated')
    if (!this.config?.clientId || !this.config?.clientSecret)
      throw new Error('Google Drive not configured')

    // Refresh if expired (with 5 min buffer)
    if (Date.now() >= this.token.expiry_date - 300000) {
      await this.refreshAccessToken()
    }

    if (!this.token?.access_token) throw new Error('Failed to obtain access token')
    return this.token.access_token
  }

  /**
   * Find or create the "KPT_Backups" folder in Google Drive
   */
  private async getOrCreateFolder(): Promise<string> {
    const token = await this.getAccessToken()

    // Search for existing folder
    const query = encodeURIComponent(
      "name='KPT_Backups' and mimeType='application/vnd.google-apps.folder' and trashed=false"
    )
    const searchResp = await this.httpGet(
      `https://www.googleapis.com/drive/v3/files?q=${query}&fields=files(id,name)`,
      token
    )
    const searchData = JSON.parse(searchResp)

    if (searchData.files && searchData.files.length > 0) {
      return searchData.files[0].id
    }

    // Create folder
    const metadata = JSON.stringify({
      name: 'KPT_Backups',
      mimeType: 'application/vnd.google-apps.folder'
    })

    const createResp = await this.httpPost(
      'https://www.googleapis.com/drive/v3/files',
      metadata,
      'application/json',
      token
    )
    const createData = JSON.parse(createResp)
    return createData.id
  }

  /**
   * Upload a file to Google Drive
   */
  async uploadFile(filePath: string, folderId: string): Promise<{ id: string; name: string }> {
    const token = await this.getAccessToken()
    const fileName = basename(filePath)
    const fileStats = statSync(filePath)
    const fileContent = readFileSync(filePath)

    // Use multipart upload for files < 5MB, resumable for larger
    const boundary = '-------314159265358979323846'
    const metadata = JSON.stringify({
      name: fileName,
      parents: [folderId]
    })

    const multipartBody = Buffer.concat([
      Buffer.from(
        `--${boundary}\r\nContent-Type: application/json; charset=UTF-8\r\n\r\n${metadata}\r\n--${boundary}\r\nContent-Type: application/octet-stream\r\n\r\n`
      ),
      fileContent,
      Buffer.from(`\r\n--${boundary}--`)
    ])

    const response = await this.httpPostBuffer(
      'https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id,name,size',
      multipartBody,
      `multipart/related; boundary=${boundary}`,
      token
    )
    const data = JSON.parse(response)

    log.info(`Uploaded to Google Drive: ${fileName} (${fileStats.size} bytes) -> ${data.id}`)
    return { id: data.id, name: data.name }
  }

  /**
   * Create a backup and upload to Google Drive
   */
  async backupToCloud(): Promise<{
    success: boolean
    localPath: string
    driveFileId?: string
    driveFileName?: string
    error?: string
  }> {
    try {
      // First create a local backup
      const backup = await backupService.createBackup()
      if (!backup.success) {
        return { success: false, localPath: '', error: 'Local backup failed' }
      }

      // Upload to Google Drive
      const folderId = await this.getOrCreateFolder()
      const result = await this.uploadFile(backup.path, folderId)

      log.info(`Cloud backup successful: ${result.name} (Drive ID: ${result.id})`)

      return {
        success: true,
        localPath: backup.path,
        driveFileId: result.id,
        driveFileName: result.name
      }
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err)
      log.error(`Cloud backup failed: ${msg}`)
      return { success: false, localPath: '', error: msg }
    }
  }

  /**
   * List backups stored in Google Drive
   */
  async listCloudBackups(): Promise<
    { id: string; name: string; size: string; modifiedTime: string }[]
  > {
    try {
      const token = await this.getAccessToken()
      const folderId = await this.getOrCreateFolder()

      const query = encodeURIComponent(`'${folderId}' in parents and trashed=false`)
      const resp = await this.httpGet(
        `https://www.googleapis.com/drive/v3/files?q=${query}&fields=files(id,name,size,modifiedTime)&orderBy=modifiedTime desc&pageSize=50`,
        token
      )
      const data = JSON.parse(resp)
      return data.files || []
    } catch (err) {
      log.error('Failed to list cloud backups:', err)
      return []
    }
  }

  /**
   * Download a backup from Google Drive
   */
  async downloadBackup(
    fileId: string,
    fileName: string
  ): Promise<{ success: boolean; path: string }> {
    try {
      const token = await this.getAccessToken()
      const backupDir = getBackupDir()
      const filePath = join(backupDir, fileName)

      const resp = await this.httpGetBuffer(
        `https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`,
        token
      )

      writeFileSync(filePath, resp)
      log.info(`Downloaded cloud backup: ${fileName}`)
      return { success: true, path: filePath }
    } catch (err) {
      log.error('Failed to download cloud backup:', err)
      return { success: false, path: '' }
    }
  }

  /**
   * Disconnect / logout
   */
  disconnect(): void {
    this.token = null
    const tokenPath = getTokenPath()
    if (existsSync(tokenPath)) {
      try {
        writeFileSync(tokenPath, '')
      } catch {
        /* ignore */
      }
    }
  }

  getStatus(): {
    configured: boolean
    authenticated: boolean
    hasRefreshToken: boolean
  } {
    return {
      configured: this.isConfigured(),
      authenticated: this.isAuthenticated(),
      hasRefreshToken: !!this.token?.refresh_token
    }
  }

  // ---- HTTP Helpers using native fetch ----

  private async httpGet(url: string, token: string): Promise<string> {
    if (!url || !token) throw new Error('Invalid URL or token for HTTP request')

    const response = await fetch(url, {
      method: 'GET',
      headers: { Authorization: `Bearer ${token}` }
    })
    const body = await response.text()
    if (!response.ok) throw new Error(`HTTP ${response.status}: ${body}`)
    return body
  }

  private async httpGetBuffer(url: string, token: string): Promise<Buffer> {
    if (!url || !token) throw new Error('Invalid URL or token for HTTP request')

    const response = await fetch(url, {
      method: 'GET',
      headers: { Authorization: `Bearer ${token}` }
    })
    if (!response.ok) throw new Error(`HTTP ${response.status}`)
    const arrayBuf = await response.arrayBuffer()
    return Buffer.from(arrayBuf)
  }

  private async httpPost(
    url: string,
    body: string,
    contentType: string,
    token?: string
  ): Promise<string> {
    if (!url) throw new Error('Invalid URL for HTTP request')

    const headers: Record<string, string> = { 'Content-Type': contentType }
    if (token) headers['Authorization'] = `Bearer ${token}`

    const response = await fetch(url, {
      method: 'POST',
      headers,
      body
    })
    const responseBody = await response.text()
    if (!response.ok) throw new Error(`HTTP ${response.status}: ${responseBody}`)
    return responseBody
  }

  private async httpPostBuffer(
    url: string,
    body: Buffer,
    contentType: string,
    token?: string
  ): Promise<string> {
    if (!url) throw new Error('Invalid URL for HTTP request')

    const headers: Record<string, string> = {
      'Content-Type': contentType,
      'Content-Length': body.length.toString()
    }
    if (token) headers['Authorization'] = `Bearer ${token}`

    const response = await fetch(url, {
      method: 'POST',
      headers,
      body: body as unknown as BodyInit
    })
    const responseBody = await response.text()
    if (!response.ok) throw new Error(`HTTP ${response.status}: ${responseBody}`)
    return responseBody
  }
}

export const cloudBackupService = new CloudBackupService()

