    const customers = customerRepo.getAll()
    const creditCustomers = customerRepo.getWithCredit()

    const wb = XLSX.utils.book_new()

    // All customers
    const rows = customers.map((c) => ({
      Name: c.name,
      Phone: c.phone,
      Email: c.email || '',
