function getPdfDir(): string {
  const userDataPath = app.getPath('userData')
  const pdfDir = join(userDataPath, 'receipts')
  if (!existsSync(pdfDir)) {
    mkdirSync(pdfDir, { recursive: true })
  }
  return pdfDir
}

function fmt(amount: number): string {
  return new Intl.NumberFormat('en-IN', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  }).format(amount)
}

function fmtCurrency(amount: number): string {
  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  }).format(amount)
}

function n(val: unknown): number {
  if (val == null) return 0
  const v = Number(val)
  return isNaN(v) ? 0 : v
}

const ONES = [
  '',
  'One',
  'Two',
  'Three',
  'Four',
  'Five',
  'Six',
  'Seven',
  'Eight',
  'Nine',
  'Ten',
  'Eleven',
  'Twelve',
  'Thirteen',
  'Fourteen',
  'Fifteen',
  'Sixteen',
  'Seventeen',
  'Eighteen',
  'Nineteen'
]
const TENS = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety']

function numberToWords(num: number): string {
  if (num === 0) return 'Zero'
  num = Math.round(Math.abs(num) * 100) / 100
  const rupees = Math.floor(num)
  const paise = Math.round((num - rupees) * 100)

  function convert(n: number): string {
    if (n < 20) return ONES[n]
    if (n < 100) return TENS[Math.floor(n / 10)] + (n % 10 ? ' ' + ONES[n % 10] : '')
    if (n < 1000)
      return ONES[Math.floor(n / 100)] + ' Hundred' + (n % 100 ? ' and ' + convert(n % 100) : '')
    if (n < 100000)
      return convert(Math.floor(n / 1000)) + ' Thousand' + (n % 1000 ? ' ' + convert(n % 1000) : '')
    if (n < 10000000)
      return (
        convert(Math.floor(n / 100000)) + ' Lakh' + (n % 100000 ? ' ' + convert(n % 100000) : '')
      )
    return (
      convert(Math.floor(n / 10000000)) +
      ' Crore' +
      (n % 10000000 ? ' ' + convert(n % 10000000) : '')
    )
  }

  let result = 'Rupees ' + convert(rupees)
  if (paise > 0) result += ' and ' + convert(paise) + ' Paise'
  result += ' Only'
  return result
}

function formatDate(date: string): string {
  try {
    const d = new Date(date + 'T00:00:00')
    return d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })
  } catch {
    return date
  }
}

function buildReturnsHtml(bill: Bill): string {
  const returns = (bill as any).returns as
    | Array<{
        type: string
