import { Label } from '../ui/label'
import { Badge } from '../ui/badge'
import { Separator } from '../ui/separator'
import { ScrollArea } from '../ui/scroll-area'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogDescription
} from '../ui/dialog'
import {
  Search,
  RotateCcw,
  ArrowLeftRight,
  Minus,
  Plus,
  Package,
  AlertCircle,
  Check,
  FileText,
  Trash2,
  History,
  PackagePlus,
  Printer,
  Download,
  Smartphone
} from 'lucide-react'
import { formatCurrency } from '../../lib/utils'
import { toast } from 'sonner'
import type {
  Bill,
  BillItem,
  Product,
  ReturnItem,
  ExchangeItem,
  BillReturnData,
  BillReturnResult
} from '@shared/types'

interface EditBillDialogProps {
  open: boolean
  onClose: () => void
  /** When set, auto-loads this bill and skips the search step */
  initialBillId?: number
}

type Step = 'search' | 'edit' | 'confirm' | 'done'
type Mode = 'return' | 'exchange'

export function EditBillDialog({
  open,
  onClose,
  initialBillId
}: EditBillDialogProps): React.JSX.Element {
  // Steps
  const [step, setStep] = useState<Step>('search')

  // Bill search
  const [searchQuery, setSearchQuery] = useState('')
  const [searchResults, setSearchResults] = useState<Bill[]>([])
  const [selectedBillIdx, setSelectedBillIdx] = useState(0)
  const [searching, setSearching] = useState(false)
  const searchRef = useRef<HTMLInputElement>(null)
  const billListRef = useRef<HTMLDivElement>(null)

  // Selected bill
  const [bill, setBill] = useState<Bill | null>(null)
  const [returnedQtyMap, setReturnedQtyMap] = useState<Record<number, number>>({})
  const [returnHistory, setReturnHistory] = useState<Record<string, unknown>[]>([])
  const [showHistory, setShowHistory] = useState(false)

  // Return items state: keyed by bill_item id
  const [returnQtys, setReturnQtys] = useState<Record<number, number>>({})

  // Mode & reason
  const [mode, setMode] = useState<Mode>('return')
  const [reason, setReason] = useState('')
  const [refundMode, setRefundMode] = useState<'cash' | 'credit' | 'adjust'>('cash')

  // Exchange items
  const [exchangeItems, setExchangeItems] = useState<ExchangeItem[]>([])
  const [exSearchQuery, setExSearchQuery] = useState('')
  const [exSearchResults, setExSearchResults] = useState<Product[]>([])
  const [exSearchSelectedIdx, setExSearchSelectedIdx] = useState(0)
  const [showExSearch, setShowExSearch] = useState(false)

  // Processing
  const [processing, setProcessing] = useState(false)
  const [result, setResult] = useState<BillReturnResult | null>(null)

  // Reset everything when dialog opens/closes
  useEffect(() => {
    if (open) {
      setSearchQuery('')
      setSearchResults([])
      setSelectedBillIdx(0)
      setBill(null)
      setReturnQtys({})
      setMode('return')
      setReason('')
      setRefundMode('cash')
      setExchangeItems([])
      setExSearchQuery('')
      setExSearchResults([])
      setExSearchSelectedIdx(0)
      setResult(null)
      setReturnedQtyMap({})
      setReturnHistory([])
      setShowHistory(false)

      // If initialBillId is provided, auto-load that bill
      if (initialBillId) {
        setStep('search') // brief loading state
        window.api.billing.getById(initialBillId).then((full) => {
          if (full && full.items?.length) {
            // Use selectBill-like logic inline
            setBill(full)
            window.api.billing.getReturnedQtyMap(full.id).then(setReturnedQtyMap)
            window.api.billing.getReturnHistory(full.id).then(setReturnHistory)
            const qtys: Record<number, number> = {}
            for (const item of full.items) qtys[Number(item.id)] = 0
            setReturnQtys(qtys)
            // Default refund mode to match how the customer originally paid
            if (full.paymentMode === 'credit' && full.customerId) setRefundMode('credit')
            else setRefundMode('cash') // cash, UPI, card ΓåÆ refund in cash
            setStep('edit')
          } else {
            toast.error('Could not load bill details')
            setStep('search')
            setTimeout(() => searchRef.current?.focus(), 100)
          }
        })
      } else {
        setStep('search')
        setTimeout(() => searchRef.current?.focus(), 100)
      }
    }
  }, [open, initialBillId])

  // ---- Bill Search ----
  const handleBillSearch = useCallback(async (term: string) => {
    setSearchQuery(term)
    setSelectedBillIdx(0)
    if (term.length < 2) {
      setSearchResults([])
      return
    }
    setSearching(true)
    try {
      const bills = await window.api.billing.quickSearch(term)
      // Only show completed / partially returned bills
      setSearchResults(bills.filter((b) => b.status !== 'cancelled'))
    } catch {
      setSearchResults([])
    }
    setSearching(false)
  }, [])

  const selectBill = useCallback(async (b: Bill) => {
    // Load full bill with items
    const full = await window.api.billing.getById(b.id)
    if (!full || !full.items?.length) {
      toast.error('Could not load bill details')
      return
    }
    setBill(full)

    // Load already-returned quantities
    const qtyMap = await window.api.billing.getReturnedQtyMap(full.id)
    setReturnedQtyMap(qtyMap)

    // Load return history
    const history = await window.api.billing.getReturnHistory(full.id)
    setReturnHistory(history)

    // Init return qtys to 0
    const qtys: Record<number, number> = {}
    for (const item of full.items) {
      qtys[Number(item.id)] = 0
    }
    setReturnQtys(qtys)

    // Default refund mode to match how the customer originally paid
    if (full.paymentMode === 'credit' && full.customerId) setRefundMode('credit')
    else setRefundMode('cash') // cash, UPI, card ΓåÆ refund in cash

    setStep('edit')
  }, [])

  // ---- Exchange Product Search ----
  const handleExSearch = useCallback(async (term: string) => {
    setExSearchQuery(term)
    setExSearchSelectedIdx(0)
    if (term.length < 2) {
      setExSearchResults([])
      setShowExSearch(false)
      return
    }
    try {
      const products = await window.api.products.search(term)
      setExSearchResults(products.slice(0, 10))
      setShowExSearch(products.length > 0)
    } catch {
      setExSearchResults([])
    }
  }, [])

  const addExchangeItem = (product: Product): void => {
    // Check if already in exchange list
    const existing = exchangeItems.findIndex((e) => e.productId === product.id)
    if (existing >= 0) {
      const updated = [...exchangeItems]
      updated[existing].quantity += 1
      setExchangeItems(updated)
    } else {
      setExchangeItems([
        ...exchangeItems,
        {
          productId: product.id,
          productName: product.name,
          sku: product.sku || '',
          hsn: product.hsnCode || '',
          price: product.sellingPrice,
          quantity: 1,
          discount: 0,
          discountType: 'percentage',
          gstRate: product.gstRate
        }
      ])
    }
    setExSearchQuery('')
    setExSearchResults([])
    setShowExSearch(false)
  }

  const addCustomExchangeItem = (): void => {
    setExchangeItems([
      ...exchangeItems,
      {
        productId: null,
        productName: 'Custom Item',
        sku: '',
        hsn: '',
        price: 0,
        quantity: 1,
        discount: 0,
        discountType: 'percentage',
        gstRate: 0
      }
    ])
  }

  const updateExchangeQty = (idx: number, qty: number): void => {
    const updated = [...exchangeItems]
    updated[idx].quantity = Math.max(1, qty)
    setExchangeItems(updated)
  }

  const updateExchangePrice = (idx: number, price: number): void => {
    const updated = [...exchangeItems]
    updated[idx].price = Math.max(0, price)
    setExchangeItems(updated)
  }

  const updateExchangeDiscount = (idx: number, disc: number): void => {
    const updated = [...exchangeItems]
    updated[idx].discount = Math.max(0, disc)
    setExchangeItems(updated)
  }

  const updateExchangeName = (idx: number, name: string): void => {
    const updated = [...exchangeItems]
    updated[idx].productName = name
    setExchangeItems(updated)
  }

  const updateExchangeGst = (idx: number, gst: number): void => {
    const updated = [...exchangeItems]
    updated[idx].gstRate = Math.max(0, gst)
    setExchangeItems(updated)
  }

  const updateExchangeDiscType = (idx: number, type: 'percentage' | 'amount'): void => {
    const updated = [...exchangeItems]
    updated[idx].discountType = type
    updated[idx].discount = 0
    setExchangeItems(updated)
  }

  const removeExchangeItem = (idx: number): void => {
    setExchangeItems(exchangeItems.filter((_, i) => i !== idx))
  }

  // ---- Calculations ----
  // bill_items in DB only has cgst_rate & sgst_rate, not gst_rate.
  // mapRow produces cgstRate & sgstRate but NOT gstRate for bill items.
  const getItemGstRate = (item: BillItem): number => {
    if (item.gstRate != null && !isNaN(item.gstRate)) return item.gstRate
    return ((item as any).cgstRate || 0) + ((item as any).sgstRate || 0)
  }

  const calculateItemRefund = (item: BillItem, returnQty: number): number => {
    if (returnQty <= 0) return 0
    const lineTotal = item.price * returnQty
    let disc = 0
    const dt =
      item.discountType === 'percent'
        ? 'percentage'
        : item.discountType === 'flat'
          ? 'amount'
          : item.discountType
    if (dt === 'percentage') {
      disc = (lineTotal * (item.discount || 0)) / 100
    } else {
      // flat discount: proportion by qty
      const totalDiscountValue = item.discountAmount || item.discount || 0
      disc = item.quantity > 0 ? (totalDiscountValue / item.quantity) * returnQty : 0
    }
    const taxable = lineTotal - disc
    const gstRate = getItemGstRate(item)
    const gst = (taxable * gstRate) / 100
    return Math.round((taxable + gst) * 100) / 100
  }

  const totalReturnAmount =
    bill?.items?.reduce((sum, item) => {
      const qty = returnQtys[Number(item.id)] || 0
      return sum + calculateItemRefund(item, qty)
    }, 0) || 0

  const totalExchangeAmount = exchangeItems.reduce((sum, ei) => {
    const lineTotal = ei.price * ei.quantity
    let disc = 0
    if (ei.discountType === 'percentage') {
      disc = (lineTotal * ei.discount) / 100
    } else {
      disc = ei.discount
    }
    const taxable = lineTotal - disc
    const gst = (taxable * ei.gstRate) / 100
    return sum + taxable + gst
  }, 0)

  const netAmount = Math.round(totalExchangeAmount) - Math.round(totalReturnAmount)

  const hasReturnItems = Object.values(returnQtys).some((q) => q > 0)

  // ---- Submit ----
  const handleSubmit = async (): Promise<void> => {
    if (!bill) return
    if (!hasReturnItems) {
      toast.error('Please select at least one item to return')
      return
    }
    if (mode === 'exchange' && exchangeItems.length === 0) {
      toast.error(
        'Exchange mode requires at least one exchange item ΓÇö add a product or switch to Return Only'
      )
      return
    }

    setProcessing(true)
    try {
      const returnItems: ReturnItem[] = (bill.items || [])
        .filter((item) => (returnQtys[Number(item.id)] || 0) > 0)
        .map((item) => ({
          billItemId: Number(item.id),
          productId: item.productId,
          productName: item.productName,
          originalQty: item.quantity,
          returnQty: returnQtys[Number(item.id)],
          rate: item.price,
          gstRate: getItemGstRate(item),
          refundAmount: calculateItemRefund(item, returnQtys[Number(item.id)])
        }))

      const data: BillReturnData = {
        originalBillId: bill.id,
        type: mode,
        reason: reason.trim() || 'Customer return',
        returnItems,
        exchangeItems: mode === 'exchange' ? exchangeItems : [],
        refundMode
      }

      const res = await window.api.billing.processReturn(data)
      if (res.success) {
        setResult(res)
        setStep('done')
        toast.success('Return processed successfully!')
      } else {
        toast.error((res as unknown as { error: string }).error || 'Failed to process return')
      }
    } catch (err: unknown) {
      toast.error(err instanceof Error ? err.message : 'Failed to process return')
    }
    setProcessing(false)
  }

  // ---- Render ----
  return (
    <Dialog
      open={open}
      onOpenChange={(v) => {
        if (!v) onClose()
      }}
    >
      <DialogContent className="max-w-4xl max-h-[90vh] flex flex-col">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <RotateCcw className="h-5 w-5 text-primary" />
            {step === 'search' && 'Edit Bill ΓÇö Search'}
            {step === 'edit' && `Edit Bill ΓÇö ${bill?.billNumber || bill?.billNo}`}
            {step === 'confirm' && 'Confirm Return / Exchange'}
            {step === 'done' && (mode === 'exchange' ? 'Exchange Complete' : 'Return Complete')}
          </DialogTitle>
          <DialogDescription>
            {step === 'search' && 'Search for a bill by number, customer name, or phone'}
            {step === 'edit' && 'Select items to return and optionally add exchange items'}
            {step === 'confirm' && 'Review the return/exchange details before confirming'}
            {step === 'done' && 'The return has been processed successfully'}
          </DialogDescription>
        </DialogHeader>

        {/* ==================== STEP 1: SEARCH ==================== */}
        {step === 'search' && (
          <div className="flex-1 space-y-4 py-2">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                ref={searchRef}
                value={searchQuery}
                onChange={(e) => handleBillSearch(e.target.value)}
                placeholder="Search by bill number, customer name, or phone..."
                className="pl-9 h-10"
                onKeyDown={(e) => {
                  if (e.key === 'ArrowDown') {
                    e.preventDefault()
                    setSelectedBillIdx((i) => {
                      const next = Math.min(i + 1, searchResults.length - 1)
                      billListRef.current?.children[next]?.scrollIntoView({ block: 'nearest' })
                      return next
                    })
                  } else if (e.key === 'ArrowUp') {
                    e.preventDefault()
                    setSelectedBillIdx((i) => {
                      const next = Math.max(i - 1, 0)
                      billListRef.current?.children[next]?.scrollIntoView({ block: 'nearest' })
                      return next
                    })
                  } else if (e.key === 'Enter' && searchResults.length > 0) {
                    e.preventDefault()
                    selectBill(searchResults[selectedBillIdx])
                  }
                }}
              />
            </div>

            <ScrollArea className="h-[400px]">
              {searching && (
                <div className="text-center py-8 text-sm text-muted-foreground">Searching...</div>
              )}
              {!searching && searchQuery.length >= 2 && searchResults.length === 0 && (
                <div className="text-center py-8 text-sm text-muted-foreground">
                  No bills found for &ldquo;{searchQuery}&rdquo;
                </div>
              )}
              <div ref={billListRef}>
                {searchResults.map((b, idx) => (
                  <button
                    key={b.id}
                    className={`flex w-full items-center gap-3 rounded-lg px-3 py-3 text-left text-sm transition-colors border-b border-border/30 ${
                      idx === selectedBillIdx ? 'bg-accent' : 'hover:bg-accent/50'
                    }`}
                    onClick={() => selectBill(b)}
                    onMouseEnter={() => setSelectedBillIdx(idx)}
                  >
                    <FileText className="h-4 w-4 shrink-0 text-primary" />
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="font-medium font-mono text-xs">
                          {b.billNumber || b.billNo}
                        </span>
                        <Badge
                          variant={b.status === 'completed' ? 'default' : 'secondary'}
                          className={`text-[10px] ${
                            b.status === 'completed'
                              ? 'bg-green-100 text-green-700 hover:bg-green-100'
                              : b.status === 'returned'
                                ? 'bg-orange-100 text-orange-700 hover:bg-orange-100'
                                : 'bg-red-100 text-red-700'
                          }`}
                        >
                          {b.status}
                        </Badge>
                      </div>
                      <div className="flex items-center gap-3 text-xs text-muted-foreground mt-0.5">
                        <span>{b.customerName || 'Walk-in'}</span>
                        <span>{b.date}</span>
                        <span>{b.totalItems} items</span>
                      </div>
                    </div>
                    <div className="text-right shrink-0">
                      <div className="font-amount font-medium">{formatCurrency(b.grandTotal)}</div>
                      <div className="text-[10px] text-muted-foreground capitalize">
                        {b.paymentMode}
                      </div>
                    </div>
                  </button>
                ))}
              </div>
            </ScrollArea>
          </div>
        )}

        {/* ==================== STEP 2: EDIT ==================== */}
        {step === 'edit' && bill && (
          <div className="flex-1 flex flex-col gap-3 overflow-hidden py-1">
            {/* Bill Info Bar */}
            <div className="flex items-center justify-between rounded-lg bg-muted/50 px-3 py-2 text-sm">
              <div className="flex items-center gap-4">
                <span className="font-mono font-medium text-primary">
                  {bill.billNumber || bill.billNo}
                </span>
                <span>{bill.customerName || 'Walk-in'}</span>
                <span className="text-muted-foreground">{bill.date}</span>
                <span
                  className={`text-[11px] font-semibold uppercase px-1.5 py-0.5 rounded ${
                    bill.paymentMode === 'credit'
                      ? 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400'
                      : bill.paymentMode === 'upi'
                        ? 'bg-blue-100 text-blue-700'
                        : bill.paymentMode === 'card'
                          ? 'bg-purple-100 text-purple-700'
                          : 'bg-green-100 text-green-700'
                  }`}
                >
                  {bill.paymentMode}
                </span>
              </div>
              <div className="flex items-center gap-3">
                <span className="font-amount font-medium">{formatCurrency(bill.grandTotal)}</span>
                {returnHistory.length > 0 && (
                  <button
                    onClick={() => setShowHistory(!showHistory)}
                    className="flex items-center gap-1 text-xs text-primary hover:underline"
                  >
                    <History className="h-3 w-3" />
                    {returnHistory.length} prior return{returnHistory.length > 1 ? 's' : ''}
                  </button>
                )}
              </div>
            </div>

            {/* Return History (collapsible) */}
            {showHistory && returnHistory.length > 0 && (
              <div className="rounded-lg border border-orange-200 bg-orange-50 dark:bg-orange-900/10 p-3 space-y-1">
                <div className="text-xs font-semibold text-orange-700 dark:text-orange-400 mb-1">
                  Previous Returns
                </div>
                {returnHistory.map((rh, i) => (
                  <div
                    key={i}
                    className="flex justify-between text-xs text-orange-600 dark:text-orange-300"
                  >
                    <div className="flex items-center gap-2">
                      <span
                        className={`uppercase font-bold tracking-wide ${
                          rh.type === 'exchange' ? 'text-blue-600 dark:text-blue-400' : ''
                        }`}
                      >
                        [{rh.type as string}]
                      </span>
                      <span>{rh.items_summary as string}</span>
                    </div>
                    <div className="flex items-center gap-3 shrink-0">
                      {(rh.return_amount as number) > 0 && (
                        <span className="font-amount">
                          Refund: {formatCurrency(rh.return_amount as number)}
                        </span>
                      )}
                      {(rh.exchange_amount as number) > 0 && (
                        <span className="font-amount text-blue-600">
                          Exchange: {formatCurrency(rh.exchange_amount as number)}
                        </span>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* Mode Toggle */}
            <div className="flex items-center gap-2">
              <button
                onClick={() => {
                  setMode('return')
                  // Reset adjust mode since it's only for exchange
                  if (refundMode === 'adjust') setRefundMode('cash')
                }}
                className={`flex items-center gap-1.5 rounded-lg border-2 px-4 py-2 text-sm font-medium transition-all ${
                  mode === 'return'
                    ? 'border-primary bg-primary/10 text-primary'
                    : 'border-border hover:bg-accent'
                }`}
              >
                <RotateCcw className="h-4 w-4" />
                Return Only
              </button>
              <button
                onClick={() => setMode('exchange')}
                className={`flex items-center gap-1.5 rounded-lg border-2 px-4 py-2 text-sm font-medium transition-all ${
                  mode === 'exchange'
                    ? 'border-primary bg-primary/10 text-primary'
                    : 'border-border hover:bg-accent'
                }`}
              >
                <ArrowLeftRight className="h-4 w-4" />
                Exchange
                {exchangeItems.length > 0 && (
                  <span className="ml-1 flex h-4 w-4 items-center justify-center rounded-full bg-primary text-[10px] text-primary-foreground">
                    {exchangeItems.length}
                  </span>
                )}
              </button>

              <div className="flex-1" />

              {/* Refund Mode */}
              <div className="flex items-center gap-2">
                <span className="text-xs text-muted-foreground">Refund via:</span>
                {(['cash', 'credit', 'adjust'] as const)
                  .filter((rm) => {
                    // Credit only available for customers with linked accounts
                    if (rm === 'credit' && !bill.customerId) return false
                    // If original was a credit sale, only allow credit refund (cannot give cash for credit owed)
                    if (rm === 'cash' && bill.paymentMode === 'credit') return false
                    // Net-off only makes sense in exchange mode
                    if (rm === 'adjust' && mode !== 'exchange') return false
                    return true
                  })
                  .map((rm) => (
                    <button
                      key={rm}
                      onClick={() => setRefundMode(rm)}
                      title={
                        rm === 'cash'
                          ? 'Give cash back to the customer'
                          : rm === 'credit'
                            ? 'Reduce the outstanding credit balance by the return amount'
                            : 'Net off: customer pays only the difference between exchange total and return value'
                      }
                      className={`rounded-md px-3 py-1.5 text-xs font-medium transition-all ${
                        refundMode === rm
                          ? 'bg-primary text-primary-foreground'
                          : 'bg-muted hover:bg-accent text-muted-foreground'
                      }`}
                    >
                      {rm === 'cash' ? 'Cash' : rm === 'credit' ? 'Credit Account' : 'Net Off'}
                    </button>
                  ))}
              </div>
            </div>

            {/* Two-pane layout for return items + exchange items */}
            <div className={`flex-1 overflow-hidden flex gap-3 ${mode === 'return' ? '' : ''}`}>
              {/* Left: Return Items */}
              <div
                className={`flex flex-col overflow-hidden ${mode === 'exchange' ? 'w-1/2' : 'w-full'}`}
              >
                <div className="flex items-center justify-between mb-1 px-1">
                  <div className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                    Return Items
                  </div>
                  <button
                    className="text-[10px] text-primary hover:underline font-medium"
                    onClick={() => {
                      const allMax: Record<number, number> = {}
                      for (const item of bill.items || []) {
                        const itemId = Number(item.id)
                        const alreadyReturned = returnedQtyMap[itemId] || 0
                        allMax[itemId] = Math.max(0, item.quantity - alreadyReturned)
                      }
                      setReturnQtys(allMax)
                    }}
                  >
                    Return All
                  </button>
                </div>
                <ScrollArea className="flex-1 rounded-lg border border-border">
                  <table className="w-full">
                    <thead className="sticky top-0 bg-muted/90 backdrop-blur-sm border-b text-[11px] uppercase tracking-wider text-muted-foreground/70">
                      <tr>
                        <th className="px-3 py-2 text-left">Product</th>
                        <th className="px-2 py-2 text-right w-[80px]">Price</th>
                        <th className="px-2 py-2 text-center w-[80px]">Qty</th>
                        <th className="px-2 py-2 text-center w-[130px]">Return Qty</th>
                        <th className="px-2 py-2 text-right w-[90px]">Refund</th>
                      </tr>
                    </thead>
                    <tbody>
                      {bill.items?.map((item) => {
                        const itemId = Number(item.id)
                        const alreadyReturned = returnedQtyMap[itemId] || 0
                        const available = item.quantity - alreadyReturned
                        const returnQty = returnQtys[itemId] || 0
                        const refund = calculateItemRefund(item, returnQty)

                        return (
                          <tr
                            key={item.id}
                            className={`border-b border-border/30 text-sm transition-colors ${
                              returnQty > 0 ? 'bg-red-50 dark:bg-red-900/10' : 'hover:bg-accent/30'
                            } ${available <= 0 ? 'opacity-40' : ''}`}
                          >
                            <td className="px-3 py-2.5">
                              <div className="font-medium text-sm leading-tight">
                                {item.productName}
                              </div>
                              <div className="text-[10px] text-muted-foreground">
                                {item.sku && <span>{item.sku} ┬╖ </span>}
                                GST: {getItemGstRate(item)}%
                                {item.discount > 0 && (
                                  <span>
                                    {' '}
                                    ┬╖ Disc: {item.discount}
                                    {item.discountType === 'percentage' ||
                                    item.discountType === 'percent'
                                      ? '%'
                                      : 'Γé╣'}
                                  </span>
                                )}
                              </div>
                              {alreadyReturned > 0 && (
                                <div className="text-[10px] text-orange-500 font-medium mt-0.5">
                                  {alreadyReturned} already returned
                                </div>
                              )}
                            </td>
                            <td className="px-2 py-2.5 text-right font-amount text-muted-foreground">
                              {formatCurrency(item.price)}
                            </td>
                            <td className="px-2 py-2.5 text-center">
                              <div className="font-medium">{item.quantity}</div>
                              {alreadyReturned > 0 && (
                                <div className="text-[10px] text-orange-500 font-medium">
                                  {available} left
                                </div>
                              )}
                            </td>
                            <td className="px-2 py-2.5">
                              {available > 0 ? (
                                <div className="flex items-center justify-center gap-1">
                                  <Button
                                    variant="outline"
                                    size="sm"
                                    className="h-7 w-7 p-0 rounded-lg"
                                    disabled={returnQty <= 0}
                                    onClick={() =>
                                      setReturnQtys({ ...returnQtys, [itemId]: returnQty - 1 })
                                    }
                                  >
                                    <Minus className="h-3 w-3" />
                                  </Button>
                                  <Input
                                    type="number"
                                    min={0}
                                    max={available}
                                    value={returnQty}
                                    onChange={(e) => {
                                      const v = Math.max(
                                        0,
                                        Math.min(available, parseInt(e.target.value) || 0)
                                      )
                                      setReturnQtys({ ...returnQtys, [itemId]: v })
                                    }}
                                    className="h-7 w-12 text-center text-sm px-1 font-semibold rounded-lg"
                                  />
                                  <Button
                                    variant="outline"
                                    size="sm"
                                    className="h-7 w-7 p-0 rounded-lg"
                                    disabled={returnQty >= available}
                                    onClick={() =>
                                      setReturnQtys({ ...returnQtys, [itemId]: returnQty + 1 })
                                    }
                                  >
                                    <Plus className="h-3 w-3" />
                                  </Button>
                                  {available > 1 && (
                                    <button
                                      className="text-[10px] text-primary hover:underline ml-1"
                                      onClick={() =>
                                        setReturnQtys({ ...returnQtys, [itemId]: available })
                                      }
                                    >
                                      All
                                    </button>
                                  )}
                                </div>
                              ) : (
                                <div className="text-xs text-center text-muted-foreground">
                                  Fully returned
                                </div>
                              )}
                            </td>
                            <td className="px-2 py-2.5 text-right font-amount font-medium">
                              {returnQty > 0 ? (
                                <span className="text-red-600 dark:text-red-400">
                                  -{formatCurrency(refund)}
                                </span>
                              ) : (
                                <span className="text-muted-foreground/40">ΓÇö</span>
                              )}
                            </td>
                          </tr>
                        )
                      })}
                    </tbody>
                  </table>
                </ScrollArea>
              </div>

              {/* Right: Exchange Items (only in exchange mode) */}
              {mode === 'exchange' && (
                <div className="w-1/2 flex flex-col overflow-hidden">
                  <div className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-1 px-1">
                    Exchange Items (New)
                  </div>
                  <div className="flex-1 rounded-lg border border-border flex flex-col overflow-hidden">
                    {/* Product search for exchange */}
                    <div className="p-2 border-b border-border relative">
                      <div className="flex gap-2">
                        <div className="relative flex-1">
                          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground" />
                          <Input
                            value={exSearchQuery}
                            onChange={(e) => handleExSearch(e.target.value)}
                            onFocus={() => exSearchResults.length > 0 && setShowExSearch(true)}
                            onBlur={() => setTimeout(() => setShowExSearch(false), 200)}
                            placeholder="Search product to add..."
                            className="h-8 pl-8 text-sm"
                            onKeyDown={(e) => {
                              if (!showExSearch || exSearchResults.length === 0) return
                              if (e.key === 'ArrowDown') {
                                e.preventDefault()
                                setExSearchSelectedIdx((i) =>
                                  Math.min(i + 1, exSearchResults.length - 1)
                                )
                              } else if (e.key === 'ArrowUp') {
                                e.preventDefault()
                                setExSearchSelectedIdx((i) => Math.max(i - 1, 0))
                              } else if (e.key === 'Enter') {
                                e.preventDefault()
                                addExchangeItem(exSearchResults[exSearchSelectedIdx])
                              } else if (e.key === 'Escape') {
                                setShowExSearch(false)
                              }
                            }}
                          />
                        </div>
                        <Button
                          variant="outline"
                          size="sm"
                          className="h-8 gap-1 border-dashed border-primary/40 text-primary hover:bg-primary/5 shrink-0"
                          onClick={addCustomExchangeItem}
                        >
                          <PackagePlus className="h-3.5 w-3.5" />
                          Other
                        </Button>
                      </div>
                      {showExSearch && exSearchResults.length > 0 && (
                        <div className="absolute left-2 right-2 top-full z-50 mt-1 max-h-48 overflow-auto rounded-md border border-border bg-popover shadow-lg">
                          {exSearchResults.map((p, idx) => (
                            <button
                              key={p.id}
                              className={`flex w-full items-center justify-between px-3 py-2 text-left text-sm transition-colors ${
                                idx === exSearchSelectedIdx ? 'bg-accent' : 'hover:bg-accent/50'
                              }`}
                              onMouseEnter={() => setExSearchSelectedIdx(idx)}
                              onMouseDown={(e) => {
                                e.preventDefault()
                                addExchangeItem(p)
                              }}
                            >
                              <div>
                                <div className="font-medium">{p.name}</div>
                                <div className="text-[10px] text-muted-foreground">
                                  {p.sku} ┬╖ Stock: {p.stock}
                                </div>
                              </div>
                              <span className="font-amount text-sm">
                                {formatCurrency(p.sellingPrice)}
                              </span>
                            </button>
                          ))}
                        </div>
                      )}
                    </div>

                    {/* Exchange items list */}
                    <ScrollArea className="flex-1">
                      {exchangeItems.length === 0 ? (
                        <div className="flex flex-col items-center justify-center py-8 text-muted-foreground">
                          <Package className="h-8 w-8 text-muted-foreground/30 mb-2" />
                          <p className="text-sm">No exchange items added</p>
                          <p className="text-xs text-muted-foreground/60">Search products above</p>
                        </div>
                      ) : (
                        <div className="divide-y divide-border/30">
                          {exchangeItems.map((ei, idx) => {
                            const lineTotal = ei.price * ei.quantity
                            let disc = 0
                            if (ei.discountType === 'percentage')
                              disc = (lineTotal * ei.discount) / 100
                            else disc = ei.discount
                            const taxable = lineTotal - disc
                            const gst = (taxable * ei.gstRate) / 100
                            const itemTotal = taxable + gst

                            return (
                              <div key={idx} className="px-3 py-2.5 space-y-1.5">
                                <div className="flex items-center justify-between">
                                  {ei.productId === null ? (
                                    <Input
                                      value={ei.productName}
                                      onChange={(e) => updateExchangeName(idx, e.target.value)}
                                      placeholder="Enter item name"
                                      className="h-7 text-sm font-medium border-dashed border-primary/30 bg-primary/5 rounded-lg max-w-[200px]"
                                    />
                                  ) : (
                                    <div className="font-medium text-sm">{ei.productName}</div>
                                  )}
                                  <Button
                                    variant="ghost"
                                    size="sm"
                                    className="h-6 w-6 p-0 text-destructive"
                                    onClick={() => removeExchangeItem(idx)}
                                  >
                                    <Trash2 className="h-3 w-3" />
                                  </Button>
                                </div>
                                <div className="flex items-center gap-2">
                                  <div className="flex items-center gap-1">
                                    <Label className="text-[10px]">Qty</Label>
                                    <div className="flex items-center gap-0.5">
                                      <Button
                                        variant="outline"
                                        size="sm"
                                        className="h-6 w-6 p-0 rounded"
                                        onClick={() => updateExchangeQty(idx, ei.quantity - 1)}
                                      >
                                        <Minus className="h-2.5 w-2.5" />
                                      </Button>
                                      <Input
                                        type="number"
                                        min={1}
                                        value={ei.quantity}
                                        onChange={(e) =>
                                          updateExchangeQty(idx, parseInt(e.target.value) || 1)
                                        }
                                        className="h-6 w-10 text-center text-xs px-0.5"
                                      />
                                      <Button
                                        variant="outline"
                                        size="sm"
                                        className="h-6 w-6 p-0 rounded"
                                        onClick={() => updateExchangeQty(idx, ei.quantity + 1)}
                                      >
                                        <Plus className="h-2.5 w-2.5" />
                                      </Button>
                                    </div>
                                  </div>
                                  <div className="flex items-center gap-1">
                                    <Label className="text-[10px]">Price</Label>
                                    <Input
                                      type="number"
                                      min={0}
                                      value={ei.price || ''}
                                      onChange={(e) =>
                                        updateExchangePrice(idx, parseFloat(e.target.value) || 0)
                                      }
                                      className="h-6 w-20 text-xs font-amount text-right"
                                    />
                                  </div>
                                  <div className="flex items-center gap-1">
                                    <Label className="text-[10px]">
                                      <button
                                        onClick={() =>
                                          updateExchangeDiscType(
                                            idx,
                                            ei.discountType === 'percentage'
                                              ? 'amount'
                                              : 'percentage'
                                          )
                                        }
                                        className="text-[10px] text-primary hover:underline font-medium"
                                        title="Toggle between percentage and flat discount"
                                      >
                                        Disc{ei.discountType === 'percentage' ? '%' : 'Γé╣'}
                                      </button>
                                    </Label>
                                    <Input
                                      type="number"
                                      min={0}
                                      value={ei.discount || ''}
                                      onChange={(e) =>
                                        updateExchangeDiscount(idx, parseFloat(e.target.value) || 0)
                                      }
                                      className="h-6 w-14 text-xs text-right"
                                    />
                                  </div>
                                  {ei.productId === null && (
                                    <div className="flex items-center gap-1">
                                      <Label className="text-[10px]">GST%</Label>
                                      <Input
                                        type="number"
                                        min={0}
                                        value={ei.gstRate || ''}
                                        onChange={(e) =>
                                          updateExchangeGst(idx, parseFloat(e.target.value) || 0)
                                        }
                                        className="h-6 w-14 text-xs text-right"
                                      />
                                    </div>
                                  )}
                                  <div className="flex-1 text-right font-amount font-medium text-sm text-green-600">
                                    {formatCurrency(itemTotal)}
                                  </div>
                                </div>
                              </div>
                            )
                          })}
                        </div>
                      )}
                    </ScrollArea>
                  </div>
                </div>
              )}
            </div>

            {/* Reason Input */}
            <div className="flex items-center gap-3">
              <Label className="text-xs text-muted-foreground shrink-0">
                Reason <span className="text-muted-foreground/50">(optional)</span>
              </Label>
              <Input
                value={reason}
                onChange={(e) => setReason(e.target.value)}
                placeholder="e.g. Customer didn't like the color, defective product..."
                className="h-8 text-sm flex-1"
              />
            </div>

            {/* Summary Bar */}
            <div className="flex items-center justify-between rounded-xl bg-gradient-to-r from-muted/80 to-muted/40 px-4 py-3 border border-border/50">
              <div className="flex items-center gap-6 text-sm">
                <div>
                  <div className="text-[10px] text-muted-foreground uppercase">Return</div>
                  <div className="font-amount font-semibold text-red-600">
                    -{formatCurrency(totalReturnAmount)}
                  </div>
                </div>
                {mode === 'exchange' && (
                  <>
                    <div className="text-muted-foreground/40">+</div>
                    <div>
                      <div className="text-[10px] text-muted-foreground uppercase">Exchange</div>
                      <div className="font-amount font-semibold text-green-600">
                        {formatCurrency(Math.round(totalExchangeAmount))}
                      </div>
                    </div>
                    <div className="text-muted-foreground/40">=</div>
                  </>
                )}
                <div>
                  <div className="text-[10px] text-muted-foreground uppercase">
                    {netAmount > 0 ? 'Customer Pays' : netAmount < 0 ? 'Refund' : 'Net'}
                  </div>
                  <div
                    className={`font-amount font-bold text-lg ${
                      netAmount > 0
                        ? 'text-green-600'
                        : netAmount < 0
                          ? 'text-red-600'
                          : 'text-foreground'
                    }`}
                  >
                    {netAmount > 0
                      ? formatCurrency(netAmount)
                      : netAmount < 0
                        ? `-${formatCurrency(Math.abs(netAmount))}`
                        : formatCurrency(0)}
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-2">
                <Button
                  variant="outline"
                  onClick={() => {
                    if (initialBillId) {
                      onClose() // Close dialog if opened from bill history
                    } else {
                      setStep('search')
                      setBill(null)
                    }
                  }}
                  className="rounded-lg"
                >
                  {initialBillId ? 'Cancel' : 'Back'}
                </Button>
                <Button
                  disabled={
                    !hasReturnItems ||
                    (mode === 'exchange' && exchangeItems.length === 0) ||
                    processing
                  }
                  onClick={() => setStep('confirm')}
                  className="gap-2 rounded-lg shadow-md min-w-[140px]"
                  title={
                    !hasReturnItems
                      ? 'Select at least one item to return'
                      : mode === 'exchange' && exchangeItems.length === 0
                        ? 'Add at least one exchange item'
                        : 'Review before confirming'
                  }
                >
                  {mode === 'exchange' && hasReturnItems && exchangeItems.length === 0
                    ? 'Add Exchange Items'
                    : 'Review'}
                </Button>
              </div>
            </div>
          </div>
        )}

        {/* ==================== STEP 3: CONFIRM ==================== */}
        {step === 'confirm' && bill && (
          <div className="flex-1 min-h-0 flex flex-col overflow-hidden py-2 gap-3">
            <div className="flex-1 min-h-0 overflow-y-auto">
              <div className="space-y-3 pr-1">
                <div className="rounded-xl border border-border p-4 space-y-3">
                  <div className="text-sm font-semibold">
                    Bill: {bill.billNumber || bill.billNo}
                  </div>
                  <div className="text-sm text-muted-foreground flex flex-wrap gap-x-3 gap-y-0.5">
                    <span>
                      Customer:{' '}
                      <span className="font-medium text-foreground">
                        {bill.customerName || 'Walk-in'}
                      </span>
                    </span>
                    <span>
                      Mode:{' '}
                      <span className="font-medium text-foreground">
                        {mode === 'return' ? 'Return Only' : 'Exchange'}
                      </span>
                    </span>
                    {netAmount < 0 && (
                      <span>
                        Refund via:{' '}
                        <span className="font-medium text-foreground">
                          {refundMode === 'cash'
                            ? 'Cash to Customer'
                            : refundMode === 'credit'
                              ? 'Credit Account'
                              : 'Net Off'}
                        </span>
                      </span>
                    )}
                  </div>
                  {reason && <div className="text-sm text-muted-foreground">Reason: {reason}</div>}

                  <Separator />

                  {/* Return items summary */}
                  <div className="text-xs font-semibold text-muted-foreground uppercase">
                    Items Being Returned
                  </div>
                  {bill.items
                    ?.filter((item) => (returnQtys[Number(item.id)] || 0) > 0)
                    .map((item) => {
                      const qty = returnQtys[Number(item.id)]
                      const refund = calculateItemRefund(item, qty)
                      return (
                        <div key={item.id} className="flex justify-between text-sm">
                          <span>
                            {item.productName} ├ù {qty}
                          </span>
                          <span className="font-amount text-red-600">
                            -{formatCurrency(refund)}
                          </span>
                        </div>
                      )
                    })}

                  {/* Exchange items summary */}
                  {mode === 'exchange' && exchangeItems.length > 0 && (
                    <>
                      <Separator />
                      <div className="text-xs font-semibold text-muted-foreground uppercase">
                        Exchange Items (New)
                      </div>
                      {exchangeItems.map((ei, idx) => {
                        const lineTotal = ei.price * ei.quantity
                        let disc = 0
                        if (ei.discountType === 'percentage') disc = (lineTotal * ei.discount) / 100
                        else disc = ei.discount
                        const taxable = lineTotal - disc
                        const gst = (taxable * ei.gstRate) / 100
                        return (
                          <div key={idx} className="flex justify-between text-sm">
                            <span>
                              {ei.productName} ├ù {ei.quantity}
                            </span>
                            <span className="font-amount text-green-600">
                              {formatCurrency(taxable + gst)}
                            </span>
                          </div>
                        )
                      })}
                    </>
                  )}

                  <Separator />

                  {/* Net summary */}
                  <div className="flex justify-between font-semibold text-base">
                    <span>Return Refund</span>
                    <span className="font-amount text-red-600">
                      -{formatCurrency(totalReturnAmount)}
                    </span>
                  </div>
                  {mode === 'exchange' && (
                    <div className="flex justify-between font-semibold text-base">
                      <span>Exchange Total</span>
                      <span className="font-amount text-green-600">
                        {formatCurrency(Math.round(totalExchangeAmount))}
                      </span>
                    </div>
                  )}
                  <div className="flex justify-between font-bold text-lg pt-2 border-t border-border">
                    <span>
                      {netAmount > 0
                        ? 'Customer Pays'
                        : netAmount < 0
                          ? 'Refund to Customer'
                          : 'Net Settlement'}
                    </span>
                    <span
                      className={`font-amount ${
                        netAmount > 0 ? 'text-green-600' : netAmount < 0 ? 'text-red-600' : ''
                      }`}
                    >
                      {netAmount > 0
                        ? formatCurrency(netAmount)
                        : netAmount < 0
                          ? `-${formatCurrency(Math.abs(netAmount))}`
                          : formatCurrency(0)}
                    </span>
                  </div>

                  {/* Cashier action instruction */}
                  <div
                    className={`mt-1 p-3 rounded-lg text-sm font-medium ${
                      netAmount > 0
                        ? 'bg-green-50 dark:bg-green-900/20 text-green-800 dark:text-green-300 border border-green-200 dark:border-green-800'
                        : netAmount < 0
                          ? 'bg-red-50 dark:bg-red-900/20 text-red-800 dark:text-red-300 border border-red-200 dark:border-red-800'
                          : 'bg-muted text-muted-foreground border border-border'
                    }`}
                  >
                    {netAmount > 0 && (
                      <span>
                        ≡ƒÅ¬ Collect <strong>{formatCurrency(netAmount)}</strong> from customer
                      </span>
                    )}
                    {netAmount < 0 &&
                      (refundMode === 'credit' ? (
                        <span>
                          ≡ƒôï Credit account will be reduced by{' '}
                          <strong>{formatCurrency(Math.abs(netAmount))}</strong> ΓÇö no cash needed
                        </span>
                      ) : (
                        <span>
                          ≡ƒÆ╡ Pay back <strong>{formatCurrency(Math.abs(netAmount))}</strong> cash to
                          customer
                        </span>
                      ))}
                    {netAmount === 0 && (
                      <span>Γ£à Equal value exchange ΓÇö no money exchange needed</span>
                    )}
                  </div>
                </div>

                {/* Warning */}
                <div className="flex items-start gap-2 rounded-lg bg-yellow-50 dark:bg-yellow-900/10 border border-yellow-200 dark:border-yellow-800 p-3">
                  <AlertCircle className="h-4 w-4 text-yellow-600 shrink-0 mt-0.5" />
                  <div className="text-sm text-yellow-700 dark:text-yellow-300">
                    This action cannot be undone. Stock will be adjusted and bill records will be
                    updated.
                  </div>
                </div>
              </div>
            </div>

            <DialogFooter className="shrink-0 border-t border-border pt-3">
              <Button variant="outline" onClick={() => setStep('edit')} className="rounded-lg">
                Back
              </Button>
              <Button
                onClick={handleSubmit}
                disabled={processing}
                className="gap-2 rounded-lg shadow-md min-w-[180px]"
              >
                {processing ? (
                  'Processing...'
                ) : (
                  <>
                    <Check className="h-4 w-4" />
                    Confirm {mode === 'return' ? 'Return' : 'Exchange'}
                  </>
                )}
              </Button>
            </DialogFooter>
          </div>
        )}

        {/* ==================== STEP 4: DONE ==================== */}
        {step === 'done' && result && (
          <div className="flex-1 flex flex-col items-center justify-center py-6 gap-4">
            <div className="rounded-full bg-green-100 dark:bg-green-900/20 p-4">
              <Check className="h-8 w-8 text-green-600" />
            </div>
            <div className="text-lg font-semibold">
              {mode === 'exchange' ? 'Exchange' : 'Return'} Processed Successfully!
            </div>

            <div className="rounded-xl border border-border p-4 space-y-2 w-full max-w-sm">
              {/* Original bill reference */}
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Original Bill</span>
                <span className="font-mono text-xs">{bill?.billNumber || bill?.billNo}</span>
              </div>
              <Separator />
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Return Amount</span>
                <span className="font-amount text-red-600">
                  -{formatCurrency(result.returnAmount)}
                </span>
              </div>
              {result.exchangeAmount > 0 && (
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Exchange Amount</span>
                  <span className="font-amount text-green-600">
                    {formatCurrency(result.exchangeAmount)}
                  </span>
                </div>
              )}
              <Separator />
              <div className="flex justify-between font-semibold">
                <span>
                  {result.netAmount > 0 ? 'Customer Pays' : result.netAmount < 0 ? 'Refund' : 'Net'}
                </span>
                <span
                  className={`font-amount ${
                    result.netAmount > 0
                      ? 'text-green-600'
                      : result.netAmount < 0
                        ? 'text-red-600'
                        : ''
                  }`}
                >
                  {result.netAmount > 0
                    ? formatCurrency(result.netAmount)
                    : result.netAmount < 0
                      ? `-${formatCurrency(Math.abs(result.netAmount))}`
                      : formatCurrency(0)}
                </span>
              </div>
              {result.newBillNo && (
                <div className="flex justify-between text-sm pt-2 border-t border-border">
                  <span className="text-muted-foreground">New Exchange Bill</span>
                  <span className="font-mono text-primary">{result.newBillNo}</span>
                </div>
              )}
            </div>

            {/* ---- Print / PDF / WhatsApp Actions ---- */}
            <div className="w-full max-w-sm space-y-2">
              {/* For exchange: print the NEW exchange bill */}
              {result.newBillId && (
                <div className="flex gap-2">
                  <Button
                    variant="outline"
                    className="flex-1 gap-2 rounded-lg"
                    onClick={async () => {
                      try {
                        await window.api.billing.printReceipt(result.newBillId!)
                        toast.success('Exchange bill sent to printer')
                      } catch {
                        toast.error('Print failed')
                      }
                    }}
                  >
                    <Printer className="h-4 w-4" />
                    Print Exchange Bill
                  </Button>
                  <Button
                    variant="outline"
                    className="flex-1 gap-2 rounded-lg"
                    onClick={async () => {
                      try {
                        const r = await window.api.billing.generatePdfReceipt(result.newBillId!)
                        if (r.success && r.path) toast.success(`Saved: ${r.path}`)
                        else toast.error('PDF generation failed')
                      } catch {
                        toast.error('PDF generation failed')
                      }
                    }}
                  >
                    <Download className="h-4 w-4" />
                    Download PDF
                  </Button>
                </div>
              )}

              {/* Always offer to print/download the original bill (which is now updated) */}
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  className="flex-1 gap-2 rounded-lg"
                  onClick={async () => {
                    try {
                      await window.api.billing.printReceipt(bill!.id)
                      toast.success('Original bill receipt sent to printer')
                    } catch {
                      toast.error('Print failed')
                    }
                  }}
                >
                  <Printer className="h-4 w-4" />
                  {result.newBillId ? 'Reprint Original' : 'Print Receipt'}
                </Button>
                <Button
                  variant="outline"
                  className="flex-1 gap-2 rounded-lg"
                  onClick={async () => {
                    try {
                      const r = await window.api.billing.generatePdfReceipt(bill!.id)
                      if (r.success && r.path) toast.success(`Saved: ${r.path}`)
                      else toast.error('PDF generation failed')
                    } catch {
                      toast.error('PDF generation failed')
                    }
                  }}
                >
                  <Download className="h-4 w-4" />
                  {result.newBillId ? 'Download Original' : 'Download PDF'}
                </Button>
              </div>

              {/* WhatsApp receipt if customer has phone */}
              {bill?.customerPhone &&
                bill.customerPhone.length >= 10 &&
                (result.newBillId ? (
                  // Exchange: offer WhatsApp for both original (with return) and new exchange bill
                  <>
                    <Button
                      variant="outline"
                      className="w-full gap-2 rounded-lg text-green-600 border-green-200 hover:bg-green-50 dark:hover:bg-green-900/10"
                      onClick={async () => {
                        try {
                          const res = await window.api.whatsapp.sendBillReceipt(
                            bill!.id,
                            bill!.customerPhone!
                          )
                          if (!res.success) toast.error(res.error || 'Failed to open WhatsApp')
                          else toast.success('WhatsApp opened ΓÇö original bill')
                        } catch {
                          toast.error('Failed to open WhatsApp')
                        }
                      }}
                    >
                      <Smartphone className="h-4 w-4" />
                      WhatsApp: Original Bill (with return)
                    </Button>
                    <Button
                      variant="outline"
                      className="w-full gap-2 rounded-lg text-green-600 border-green-200 hover:bg-green-50 dark:hover:bg-green-900/10"
                      onClick={async () => {
                        try {
                          const res = await window.api.whatsapp.sendBillReceipt(
                            result.newBillId!,
                            bill!.customerPhone!
                          )
                          if (!res.success) toast.error(res.error || 'Failed to open WhatsApp')
                          else toast.success('WhatsApp opened ΓÇö exchange bill')
                        } catch {
                          toast.error('Failed to open WhatsApp')
                        }
                      }}
                    >
                      <Smartphone className="h-4 w-4" />
                      WhatsApp: Exchange Bill (new items)
                    </Button>
                  </>
                ) : (
                  <Button
                    variant="outline"
                    className="w-full gap-2 rounded-lg text-green-600 border-green-200 hover:bg-green-50 dark:hover:bg-green-900/10"
                    onClick={async () => {
                      try {
                        const res = await window.api.whatsapp.sendBillReceipt(
                          bill!.id,
                          bill!.customerPhone!
                        )
                        if (!res.success) toast.error(res.error || 'Failed to open WhatsApp')
                        else toast.success('WhatsApp opened')
                      } catch {
                        toast.error('Failed to open WhatsApp')
                      }
                    }}
                  >
                    <Smartphone className="h-4 w-4" />
                    Send via WhatsApp to {bill.customerPhone}
                  </Button>
                ))}
            </div>

            <Button onClick={onClose} className="mt-2 rounded-lg min-w-[120px]">
              Done
            </Button>
          </div>
        )}
      </DialogContent>
    </Dialog>
  )
}

// ============================================================================
// KPT Billing - Lock Screen Overlay
// Full-screen lock triggered by Ctrl+L or sidebar lock button
// ============================================================================
import { useState, useRef, useEffect, useCallback } from 'react'
import { Lock, Eye, EyeOff } from 'lucide-react'

interface LockScreenProps {
  open: boolean
  onUnlock: () => void
}

export function LockScreen({ open, onUnlock }: LockScreenProps): React.JSX.Element | null {
  const [pin, setPin] = useState('')
  const [showPin, setShowPin] = useState(false)
  const [verifying, setVerifying] = useState(false)
  const [error, setError] = useState('')
  const [time, setTime] = useState(new Date())
  const inputRef = useRef<HTMLInputElement>(null)

  // Update clock every minute
  useEffect(() => {
    if (!open) return
    const timer = setInterval(() => setTime(new Date()), 30000)
    return () => clearInterval(timer)
  }, [open])

  // Focus input when shown
  useEffect(() => {
    if (open) {
      setPin('')
      setError('')
      setTimeout(() => inputRef.current?.focus(), 100)
    }
  }, [open])

  const handleVerify = useCallback(async () => {
    if (!pin.trim() || pin.length < 4) {
      setError('Enter at least 4 digits')
      return
    }
    setVerifying(true)
    setError('')
    try {
      const result = await window.api.auth.verifyPin(pin)
      if (result.success) {
        setPin('')
        setError('')
        onUnlock()
      } else {
        setError('Incorrect PIN')
        setPin('')
        inputRef.current?.focus()
      }
    } catch {
      setError('Verification failed')
    }
    setVerifying(false)
  }, [pin, onUnlock])

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') {
        handleVerify()
      }
    },
    [handleVerify]
  )

  if (!open) return null

  const hrs = time.getHours()
  const mins = time.getMinutes().toString().padStart(2, '0')
  const period = hrs >= 12 ? 'PM' : 'AM'
  const displayHrs = hrs % 12 || 12
  const dateStr = time.toLocaleDateString('en-IN', {
    weekday: 'long',
    day: 'numeric',
    month: 'long',
    year: 'numeric'
  })

  return (
    <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-background">
      {/* Background pattern */}
      <div className="absolute inset-0 opacity-5">
        <div
          className="h-full w-full"
          style={{
            backgroundImage: 'radial-gradient(circle at 2px 2px, currentColor 1px, transparent 0)',
            backgroundSize: '40px 40px'
          }}
        />
      </div>

      {/* Clock */}
      <div className="relative mb-8 text-center">
        <p className="text-7xl font-light tracking-tight text-foreground">
          {displayHrs}:{mins}
          <span className="ml-2 text-2xl text-muted-foreground">{period}</span>
        </p>
        <p className="mt-2 text-lg text-muted-foreground">{dateStr}</p>
      </div>

      {/* Lock Card */}
      <div className="relative w-full max-w-sm space-y-6 rounded-2xl border border-border bg-card p-8 shadow-2xl">
        {/* Lock Icon */}
        <div className="flex flex-col items-center gap-3">
          <div className="flex h-16 w-16 items-center justify-center rounded-full bg-primary/10">
            <Lock className="h-8 w-8 text-primary" />
          </div>
          <div className="text-center">
            <h2 className="text-xl font-bold">Screen Locked</h2>
            <p className="text-sm text-muted-foreground mt-1">Enter PIN to unlock</p>
          </div>
        </div>

        {/* PIN Input */}
        <div className="space-y-3">
          <div className="relative">
            <input
              ref={inputRef}
              type={showPin ? 'text' : 'password'}
              value={pin}
              onChange={(e) => {
                setPin(e.target.value.replace(/\D/g, ''))
                setError('')
              }}
              onKeyDown={handleKeyDown}
              placeholder="Enter PIN"
              maxLength={8}
              className="flex h-12 w-full rounded-lg border border-input bg-background px-4 pr-12 text-center text-2xl tracking-[0.5em] ring-offset-background placeholder:text-muted-foreground placeholder:text-base placeholder:tracking-normal focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
              autoComplete="off"
              disabled={verifying}
            />
            <button
              type="button"
              onClick={() => setShowPin(!showPin)}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
              tabIndex={-1}
            >
              {showPin ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
            </button>
          </div>

          {error && <p className="text-center text-sm text-destructive">{error}</p>}

          <button
            onClick={handleVerify}
            disabled={verifying || pin.length < 4}
            className="flex h-11 w-full items-center justify-center rounded-lg bg-primary text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90 disabled:opacity-50"
          >
            {verifying ? 'Verifying...' : 'Unlock'}
          </button>
        </div>
      </div>

      {/* Footer */}
      <p className="relative mt-8 text-xs text-muted-foreground">
        Krishnapriya Textiles ΓÇö KPT Billing
      </p>
    </div>
  )
}

// ============================================================================
// KPT Billing - Quick Bill Search & Command Palette (Ctrl+K)
// Full-featured bill search with view, print, PDF, WhatsApp, return/exchange
// ============================================================================
import { useState, useEffect, useRef, useCallback } from 'react'
import {
  Search,
  FileText,
  X,
  Calendar,
  User,
  Phone,
  IndianRupee,
  Printer,
  Download,
  MessageSquare,
  RotateCcw,
  Eye,
  ArrowLeft,
  ChevronRight,
  Clock,
  Hash,
  CreditCard,
  Banknote,
  Smartphone
} from 'lucide-react'
import { formatCurrency } from '../../lib/utils'
import { toast } from 'sonner'
import { EditBillDialog } from '../billing/EditBillDialog'
import type { Bill } from '@shared/types'

interface QuickBillSearchProps {
  open: boolean
  onClose: () => void
}

type Mode = 'list' | 'actions' | 'view'

interface Action {
  id: string
  label: string
  icon: React.ComponentType<{ className?: string }>
  description: string
  shortcut?: string
  disabled?: boolean
  color?: string
}

export function QuickBillSearch({ open, onClose }: QuickBillSearchProps): React.JSX.Element | null {
  const [query, setQuery] = useState('')
  const [results, setResults] = useState<Bill[]>([])
  const [recentBills, setRecentBills] = useState<Bill[]>([])
  const [selectedIdx, setSelectedIdx] = useState(0)
  const [selectedActionIdx, setSelectedActionIdx] = useState(0)
  const [loading, setLoading] = useState(false)
  const [mode, setMode] = useState<Mode>('list')
  const [selectedBill, setSelectedBill] = useState<Bill | null>(null)
  const [fullBill, setFullBill] = useState<Bill | null>(null)
  const [loadingBill, setLoadingBill] = useState(false)
  const [showReturnDialog, setShowReturnDialog] = useState(false)
  const inputRef = useRef<HTMLInputElement>(null)
  const panelRef = useRef<HTMLDivElement>(null)
  const listRef = useRef<HTMLDivElement>(null)

  const bills = query.length >= 2 ? results : recentBills

  // Load recent bills when dialog opens
  useEffect(() => {
    if (open) {
      setQuery('')
      setResults([])
      setSelectedIdx(0)
      setSelectedActionIdx(0)
      setMode('list')
      setSelectedBill(null)
      setFullBill(null)
      setShowReturnDialog(false)
      setTimeout(() => inputRef.current?.focus(), 50)
      window.api.billing
        .getRecentBills(15)
        .then(setRecentBills)
        .catch(() => {})
    }
  }, [open])

  // Manage focus when switching modes
  useEffect(() => {
    if (!open) return
    if (mode === 'list') {
      setTimeout(() => inputRef.current?.focus(), 30)
    } else {
      setTimeout(() => panelRef.current?.focus(), 30)
    }
  }, [mode, open])

  const handleSearch = useCallback(async (term: string) => {
    setQuery(term)
    setMode('list')
    setSelectedIdx(0)
    if (term.length < 2) {
      setResults([])
      return
    }
    setLoading(true)
    try {
      const found = await window.api.billing.quickSearch(term)
      setResults(found)
    } catch {
      setResults([])
    }
    setLoading(false)
  }, [])

  const getActions = useCallback(
    (bill: Bill): Action[] => [
      {
        id: 'view',
        label: 'View Bill Details',
        icon: Eye,
        description: 'View complete bill with items and totals',
        shortcut: 'V',
        color: 'text-blue-500'
      },
      {
        id: 'print',
        label: 'Print Receipt',
        icon: Printer,
        description: 'Print thermal receipt',
        shortcut: 'P',
        color: 'text-green-500'
      },
      {
        id: 'download',
        label: 'Download PDF',
        icon: Download,
        description: 'Generate and open PDF invoice',
        shortcut: 'D',
        color: 'text-purple-500'
      },
      {
        id: 'whatsapp',
        label: 'Send via WhatsApp',
        icon: MessageSquare,
        description: bill.customerPhone
          ? `Send to ${bill.customerPhone}`
          : 'No phone number available',
        shortcut: 'W',
        disabled: !bill.customerPhone,
        color: 'text-emerald-500'
      },
      {
        id: 'return',
        label: 'Return / Exchange',
        icon: RotateCcw,
        description: 'Process return or exchange for this bill',
        shortcut: 'R',
        color: 'text-orange-500'
      }
    ],
    []
  )

  const openActions = useCallback((bill: Bill) => {
    setSelectedBill(bill)
    setSelectedActionIdx(0)
    setMode('actions')
  }, [])

  const executeAction = useCallback(async (actionId: string, bill: Bill) => {
    switch (actionId) {
      case 'view': {
        setLoadingBill(true)
        setMode('view')
        try {
          const full = await window.api.billing.getById(bill.id)
          setFullBill(full)
        } catch {
          toast.error('Failed to load bill details')
          setMode('actions')
        }
        setLoadingBill(false)
        break
      }
      case 'print': {
        try {
          toast.loading('Printing receipt...', { id: 'qbs-print' })
          await window.api.billing.printReceipt(bill.id)
          toast.success('Receipt sent to printer', { id: 'qbs-print' })
        } catch {
          toast.error('Failed to print receipt', { id: 'qbs-print' })
        }
        break
      }
      case 'download': {
        try {
          toast.loading('Generating PDF...', { id: 'qbs-pdf' })
          const result = await window.api.billing.generatePdfReceipt(bill.id)
          if (result.success) {
            await window.api.report.openFile(result.path)
            toast.success('PDF opened', { id: 'qbs-pdf' })
          }
        } catch {
          toast.error('Failed to generate PDF', { id: 'qbs-pdf' })
        }
        break
      }
      case 'whatsapp': {
        if (bill.customerPhone) {
          try {
            toast.loading('Sending via WhatsApp...', { id: 'qbs-wa' })
            await window.api.whatsapp.sendBillReceipt(bill.id, bill.customerPhone)
            toast.success('Sent via WhatsApp', { id: 'qbs-wa' })
          } catch {
            toast.error('Failed to send via WhatsApp', { id: 'qbs-wa' })
          }
        }
        break
      }
      case 'return': {
        setShowReturnDialog(true)
        break
      }
    }
  }, [])

  const goBack = useCallback(() => {
    if (mode === 'view') {
      setMode('actions')
      setFullBill(null)
    } else if (mode === 'actions') {
      setMode('list')
      setSelectedBill(null)
    }
  }, [mode])

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent): void => {
      // Don't handle keys when return dialog is open
      if (showReturnDialog) return

      if (mode === 'list') {
        if (e.key === 'ArrowDown' && bills.length > 0) {
          e.preventDefault()
          setSelectedIdx((i) => {
            const next = Math.min(i + 1, bills.length - 1)
            listRef.current?.children[next]?.scrollIntoView({ block: 'nearest' })
            return next
          })
        } else if (e.key === 'ArrowUp' && bills.length > 0) {
          e.preventDefault()
          setSelectedIdx((i) => {
            const next = Math.max(i - 1, 0)
            listRef.current?.children[next]?.scrollIntoView({ block: 'nearest' })
            return next
          })
        } else if ((e.key === 'Enter' || e.key === 'ArrowRight') && bills.length > 0) {
          e.preventDefault()
          openActions(bills[selectedIdx])
        } else if (e.key === 'Escape') {
          onClose()
        }
      } else if (mode === 'actions' && selectedBill) {
        const actions = getActions(selectedBill)
        if (e.key === 'ArrowDown') {
          e.preventDefault()
          setSelectedActionIdx((i) => {
            let next = i + 1
            while (next < actions.length && actions[next].disabled) next++
            return next < actions.length ? next : i
          })
        } else if (e.key === 'ArrowUp') {
          e.preventDefault()
          setSelectedActionIdx((i) => {
            let next = i - 1
            while (next >= 0 && actions[next].disabled) next--
            return next >= 0 ? next : i
          })
        } else if (e.key === 'Enter') {
          e.preventDefault()
          const action = actions[selectedActionIdx]
          if (!action.disabled) executeAction(action.id, selectedBill)
        } else if (e.key === 'ArrowLeft' || e.key === 'Escape') {
          e.preventDefault()
          goBack()
        } else {
          // Shortcut keys for actions
          const key = e.key.toUpperCase()
          const action = actions.find((a) => a.shortcut === key && !a.disabled)
          if (action) {
            e.preventDefault()
            executeAction(action.id, selectedBill)
          }
        }
      } else if (mode === 'view') {
        if (e.key === 'Escape' || e.key === 'ArrowLeft' || e.key === 'Backspace') {
          e.preventDefault()
          goBack()
        }
        if (selectedBill) {
          const key = e.key.toUpperCase()
          if (key === 'P') {
            e.preventDefault()
            executeAction('print', selectedBill)
          } else if (key === 'D') {
            e.preventDefault()
            executeAction('download', selectedBill)
          } else if (key === 'W' && selectedBill.customerPhone) {
            e.preventDefault()
            executeAction('whatsapp', selectedBill)
          }
        }
      }
    },
    [
      mode,
      bills,
      selectedIdx,
      selectedActionIdx,
      selectedBill,
      showReturnDialog,
      openActions,
      getActions,
      executeAction,
      goBack,
      onClose
    ]
  )

  if (!open) return null

  return (
    <>
      <div
        className={`fixed inset-0 z-[100] flex items-start justify-center pt-[12vh] ${showReturnDialog ? 'hidden' : ''}`}
      >
        {/* Backdrop */}
        <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={onClose} />

        {/* Search Panel */}
        <div
          ref={panelRef}
          tabIndex={-1}
          onKeyDown={handleKeyDown}
          className={`relative z-10 w-full rounded-xl border border-border bg-popover shadow-2xl outline-none transition-all duration-200 ${
            mode === 'view' ? 'max-w-3xl' : 'max-w-xl'
          }`}
        >
          {/* ---- Header ---- */}
          {mode === 'list' ? (
            <div className="flex items-center gap-3 border-b border-border px-4 py-3">
              <Search className="h-5 w-5 text-muted-foreground shrink-0" />
              <input
                ref={inputRef}
                value={query}
                onChange={(e) => handleSearch(e.target.value)}
                placeholder="Search bills by number, customer, phone..."
                className="flex-1 bg-transparent text-base outline-none placeholder:text-muted-foreground"
              />
              {query && (
                <button onClick={() => handleSearch('')} className="rounded-md p-1 hover:bg-accent">
                  <X className="h-3.5 w-3.5 text-muted-foreground" />
                </button>
              )}
              <button onClick={onClose} className="rounded-md p-1 hover:bg-accent">
                <X className="h-4 w-4 text-muted-foreground" />
              </button>
            </div>
          ) : (
            <div className="flex items-center gap-3 border-b border-border px-4 py-3">
              <button
                onClick={goBack}
                className="rounded-md p-1.5 hover:bg-accent transition-colors"
              >
                <ArrowLeft className="h-4 w-4 text-muted-foreground" />
              </button>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 flex-wrap">
                  <span className="font-mono text-sm font-semibold">
                    {selectedBill?.billNumber || selectedBill?.billNo}
                  </span>
                  <span className="text-xs text-muted-foreground">
                    {selectedBill?.customerName || 'Walk-in Customer'}
                  </span>
                  <span className="text-xs font-semibold text-primary flex items-center gap-0.5">
                    <IndianRupee className="h-3 w-3" />
                    {formatCurrency(selectedBill?.grandTotal || 0).replace('Γé╣', '')}
                  </span>
                </div>
              </div>
              <span className="text-[10px] font-medium text-muted-foreground uppercase tracking-wider">
                {mode === 'actions' ? 'Actions' : 'Details'}
              </span>
              <button onClick={onClose} className="rounded-md p-1 hover:bg-accent">
                <X className="h-4 w-4 text-muted-foreground" />
              </button>
            </div>
          )}

          {/* ---- Content ---- */}
          <div className="max-h-[55vh] overflow-auto">
            {/* LIST MODE */}
            {mode === 'list' && (
              <div className="p-1">
                {loading && (
                  <div className="px-4 py-8 text-center text-sm text-muted-foreground">
                    Searching...
                  </div>
                )}

                {!loading && query.length >= 2 && results.length === 0 && (
                  <div className="px-4 py-8 text-center text-sm text-muted-foreground">
                    No bills found for &ldquo;{query}&rdquo;
                  </div>
                )}

                {!loading && bills.length > 0 && (
                  <>
                    {query.length < 2 && (
                      <div className="px-3 pt-2 pb-1">
                        <span className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground/60 flex items-center gap-1.5">
                          <Clock className="h-3 w-3" />
                          Recent Bills
                        </span>
                      </div>
                    )}
                    <div ref={listRef}>
                      {bills.map((bill, idx) => (
                        <button
                          key={bill.id}
                          className={`flex w-full items-center gap-3 rounded-lg px-3 py-2.5 text-left text-sm transition-colors ${
                            idx === selectedIdx ? 'bg-accent' : 'hover:bg-accent/50'
                          }`}
                          onClick={() => openActions(bill)}
                          onMouseEnter={() => setSelectedIdx(idx)}
                        >
                          <FileText className="h-4 w-4 shrink-0 text-primary" />
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2">
                              <span className="font-medium font-mono text-xs">
                                {bill.billNumber || bill.billNo}
                              </span>
                              <span
                                className={`text-[10px] px-1.5 py-0.5 rounded-full ${
                                  bill.status === 'completed'
                                    ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400'
                                    : bill.status === 'returned'
                                      ? 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400'
                                      : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'
                                }`}
                              >
                                {bill.status}
                              </span>
                            </div>
                            <div className="flex items-center gap-3 text-xs text-muted-foreground mt-0.5">
                              <span className="flex items-center gap-1 truncate">
                                <User className="h-3 w-3 shrink-0" />
                                {bill.customerName || 'Walk-in'}
                              </span>
                              {bill.customerPhone && (
                                <span className="flex items-center gap-1">
                                  <Phone className="h-3 w-3 shrink-0" />
                                  {bill.customerPhone}
                                </span>
                              )}
                              <span className="flex items-center gap-1">
                                <Calendar className="h-3 w-3 shrink-0" />
                                {bill.date}
                              </span>
                            </div>
                          </div>
                          <div className="text-right shrink-0 flex items-center gap-2">
                            <div>
                              <div className="font-amount font-medium flex items-center gap-0.5">
                                <IndianRupee className="h-3 w-3" />
                                {formatCurrency(bill.grandTotal).replace('Γé╣', '')}
                              </div>
                              <div className="text-[10px] text-muted-foreground capitalize">
                                {bill.paymentMode}
                              </div>
                            </div>
                            <ChevronRight className="h-3.5 w-3.5 text-muted-foreground/40" />
                          </div>
                        </button>
                      ))}
                    </div>
                  </>
                )}

                {!loading && query.length < 2 && recentBills.length === 0 && (
                  <div className="px-4 py-8 text-center text-sm text-muted-foreground">
                    <div className="mb-2">Search for bills by number, customer, or phone</div>
                    <div className="text-xs opacity-60">No recent bills found</div>
                  </div>
                )}
              </div>
            )}

            {/* ACTIONS MODE */}
            {mode === 'actions' && selectedBill && (
              <div className="p-1">
                <div className="px-3 pt-2 pb-1">
                  <span className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground/60">
                    Quick Actions
                  </span>
                </div>
                {getActions(selectedBill).map((action, idx) => (
                  <button
                    key={action.id}
                    disabled={action.disabled}
                    className={`flex w-full items-center gap-3 rounded-lg px-3 py-2.5 text-left text-sm transition-colors ${
                      action.disabled
                        ? 'opacity-40 cursor-not-allowed'
                        : idx === selectedActionIdx
                          ? 'bg-accent'
                          : 'hover:bg-accent/50'
                    }`}
                    onClick={() => !action.disabled && executeAction(action.id, selectedBill)}
                    onMouseEnter={() => !action.disabled && setSelectedActionIdx(idx)}
                  >
                    <div
                      className={`flex h-8 w-8 items-center justify-center rounded-lg bg-accent/80 ${action.color || ''}`}
                    >
                      <action.icon className="h-4 w-4" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="font-medium text-sm">{action.label}</div>
                      <div className="text-xs text-muted-foreground">{action.description}</div>
                    </div>
                    {action.shortcut && !action.disabled && (
                      <kbd className="rounded-md bg-muted/80 px-1.5 py-0.5 text-[10px] font-mono text-muted-foreground/70">
                        {action.shortcut}
                      </kbd>
                    )}
                  </button>
                ))}
              </div>
            )}

            {/* VIEW MODE */}
            {mode === 'view' && (
              <div className="p-4">
                {loadingBill ? (
                  <div className="py-8 text-center text-sm text-muted-foreground">
                    Loading bill details...
                  </div>
                ) : fullBill ? (
                  <div className="space-y-4">
                    {/* Bill header info */}
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <div className="flex items-center gap-2 text-sm">
                          <Hash className="h-3.5 w-3.5 text-muted-foreground" />
                          <span className="font-mono font-semibold">
                            {fullBill.billNumber || fullBill.billNo}
                          </span>
                          <span
                            className={`text-[10px] px-1.5 py-0.5 rounded-full ${
                              fullBill.status === 'completed'
                                ? 'bg-green-100 text-green-700'
                                : fullBill.status === 'returned'
                                  ? 'bg-orange-100 text-orange-700'
                                  : 'bg-red-100 text-red-700'
                            }`}
                          >
                            {fullBill.status}
                          </span>
                        </div>
                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                          <Calendar className="h-3.5 w-3.5" />
                          <span>
                            {fullBill.date} at {fullBill.time}
                          </span>
                        </div>
                        {fullBill.salesmanName && (
                          <div className="text-xs text-muted-foreground">
                            Salesman: {fullBill.salesmanName}
                          </div>
                        )}
                      </div>
                      <div className="space-y-2">
                        <div className="flex items-center gap-2 text-sm">
                          <User className="h-3.5 w-3.5 text-muted-foreground" />
                          <span>{fullBill.customerName || 'Walk-in Customer'}</span>
                        </div>
                        {fullBill.customerPhone && (
                          <div className="flex items-center gap-2 text-sm text-muted-foreground">
                            <Phone className="h-3.5 w-3.5" />
                            <span>{fullBill.customerPhone}</span>
                          </div>
                        )}
                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                          {fullBill.paymentMode === 'cash' ? (
                            <Banknote className="h-3.5 w-3.5" />
                          ) : fullBill.paymentMode === 'upi' ? (
                            <Smartphone className="h-3.5 w-3.5" />
                          ) : (
                            <CreditCard className="h-3.5 w-3.5" />
                          )}
                          <span className="capitalize">{fullBill.paymentMode}</span>
                          {fullBill.paymentMode === 'upi' && fullBill.upiReference && (
                            <span className="text-xs text-muted-foreground/70">
                              Ref: {fullBill.upiReference}
                            </span>
                          )}
                        </div>
                      </div>
                    </div>

                    {/* Items table */}
                    {fullBill.items && fullBill.items.length > 0 && (
                      <div className="rounded-lg border border-border overflow-hidden">
                        <table className="w-full text-xs">
                          <thead>
                            <tr className="bg-muted/50 border-b border-border">
                              <th className="text-left px-3 py-2 font-medium text-muted-foreground">
                                Item
                              </th>
                              <th className="text-center px-2 py-2 font-medium text-muted-foreground">
                                Qty
                              </th>
                              <th className="text-right px-2 py-2 font-medium text-muted-foreground">
                                Price
                              </th>
                              <th className="text-right px-2 py-2 font-medium text-muted-foreground">
                                GST
                              </th>
                              <th className="text-right px-3 py-2 font-medium text-muted-foreground">
                                Total
                              </th>
                            </tr>
                          </thead>
                          <tbody>
                            {fullBill.items.map((item, i) => {
                              const isFullReturn =
                                item.returnedQty != null && item.returnedQty >= item.quantity
                              return (
                                <tr
                                  key={i}
                                  className={`border-b border-border/50 last:border-0 ${isFullReturn ? 'opacity-45 line-through' : ''}`}
                                >
                                  <td className="px-3 py-2">
                                    <div className="font-medium">{item.productName}</div>
                                    {item.sku && (
                                      <div className="text-muted-foreground">{item.sku}</div>
                                    )}
                                    {item.returnedQty != null && item.returnedQty > 0 && (
                                      <span className="text-[10px] text-orange-500 font-medium">
                                        (
                                        {isFullReturn ? 'Returned' : `${item.returnedQty} returned`}
                                        )
                                      </span>
                                    )}
