// ============================================================================
// KPT Billing - Bulk Stock Update Dialog
// Import stock from CSV/Excel for inventory counts
// ============================================================================
import { useState, useRef } from 'react'
import { Button } from '../ui/button'
import { Badge } from '../ui/badge'
import { ScrollArea } from '../ui/scroll-area'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogDescription
} from '../ui/dialog'
import { Upload, FileSpreadsheet, CheckCircle2, AlertCircle, Download, Loader2 } from 'lucide-react'
import { toast } from 'sonner'

interface ParsedRow {
  sku: string
  barcode: string
  stock: number
  raw: string
}

interface BulkStockUpdateDialogProps {
  open: boolean
  onClose: () => void
  onComplete: () => void
}

function parseCSV(text: string): ParsedRow[] {
  const lines = text.trim().split(/\r?\n/)
  if (lines.length < 2) return []

  // Detect header
  const header = lines[0].toLowerCase()
  const sep = header.includes('\t') ? '\t' : ','

  const cols = header.split(sep).map((c) => c.trim().replace(/^["']|["']$/g, ''))
  const skuIdx = cols.findIndex((c) => c === 'sku' || c === 'sku_code' || c === 'product_code')
  const barcodeIdx = cols.findIndex((c) => c === 'barcode' || c === 'bar_code' || c === 'ean')
  const stockIdx = cols.findIndex(
    (c) =>
      c === 'stock' || c === 'quantity' || c === 'qty' || c === 'current_stock' || c === 'count'
  )

  if (stockIdx === -1) return []

  const rows: ParsedRow[] = []
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i].trim()
    if (!line) continue
    const values = line.split(sep).map((v) => v.trim().replace(/^["']|["']$/g, ''))
    const stock = parseInt(values[stockIdx])
    if (isNaN(stock)) continue

    rows.push({
      sku: skuIdx >= 0 ? values[skuIdx] || '' : '',
      barcode: barcodeIdx >= 0 ? values[barcodeIdx] || '' : '',
      stock,
      raw: line
    })
  }
  return rows
}

export function BulkStockUpdateDialog({
  open,
  onClose,
  onComplete
}: BulkStockUpdateDialogProps): React.JSX.Element {
  const [parsedRows, setParsedRows] = useState<ParsedRow[]>([])
  const [fileName, setFileName] = useState('')
  const [importing, setImporting] = useState(false)
  const [result, setResult] = useState<{
    total: number
    imported: number
    skipped: number
    errors: string[]
  } | null>(null)
  const fileRef = useRef<HTMLInputElement>(null)

  const reset = (): void => {
    setParsedRows([])
    setFileName('')
    setResult(null)
  }

  const handleClose = (): void => {
    reset()
    onClose()
  }

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>): void => {
    const file = e.target.files?.[0]
    if (!file) return

    setFileName(file.name)
    setResult(null)

    const reader = new FileReader()
    reader.onload = (ev) => {
      const text = ev.target?.result as string
      if (!text) return
      const rows = parseCSV(text)
      if (rows.length === 0) {
        toast.error(
          'No valid rows found. Ensure the file has a header row with "sku" or "barcode" and "stock" or "qty" columns.'
        )
        setParsedRows([])
        return
      }
      setParsedRows(rows)
      toast.success(`Parsed ${rows.length} rows from ${file.name}`)
    }
    reader.readAsText(file)
  }

  const handleImport = async (): Promise<void> => {
    if (parsedRows.length === 0) return
    setImporting(true)
    try {
      const items = parsedRows.map((r) => ({
        sku: r.sku || undefined,
        barcode: r.barcode || undefined,
        stock: r.stock
      }))
      const res = await window.api.products.bulkStockUpdate(items)
      setResult(res)
      if (res.imported > 0) {
        toast.success(`${res.imported} products updated`)
        onComplete()
      }
      if (res.skipped > 0) {
        toast.warning(`${res.skipped} rows skipped ΓÇö see details below`)
      }
    } catch (err) {
      toast.error('Bulk update failed')
    }
    setImporting(false)
  }

  const handleDownloadTemplate = (): void => {
    const csv = 'sku,barcode,stock\nKPT-SAR-00001,,100\n,8901234567890,50\n'
    const blob = new Blob([csv], { type: 'text/csv' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = 'stock_update_template.csv'
    a.click()
    URL.revokeObjectURL(url)
  }

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="max-w-2xl">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <FileSpreadsheet className="h-5 w-5" />
            Bulk Stock Update
          </DialogTitle>
          <DialogDescription>
            Import stock counts from a CSV file. Match products by SKU or barcode.
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4 py-2">
          {/* Upload Area */}
          {!result && (
            <>
              <div
                className="flex flex-col items-center justify-center gap-3 rounded-lg border-2 border-dashed border-border p-6 cursor-pointer hover:border-primary/50 hover:bg-accent/30 transition-colors"
                onClick={() => fileRef.current?.click()}
              >
                <Upload className="h-8 w-8 text-muted-foreground" />
                <div className="text-center">
                  <p className="text-sm font-medium">{fileName || 'Click to select CSV file'}</p>
                  <p className="text-xs text-muted-foreground mt-1">
                    Required columns: <code className="bg-muted px-1 rounded">sku</code> or{' '}
                    <code className="bg-muted px-1 rounded">barcode</code> +{' '}
                    <code className="bg-muted px-1 rounded">stock</code> (or qty/quantity/count)
                  </p>
                </div>
                <input
                  ref={fileRef}
                  type="file"
                  accept=".csv,.tsv,.txt"
                  className="hidden"
                  onChange={handleFileChange}
                />
              </div>

              <Button
                variant="link"
                size="sm"
                onClick={handleDownloadTemplate}
                className="gap-1 text-xs h-auto p-0"
              >
                <Download className="h-3 w-3" />
                Download CSV template
              </Button>
            </>
          )}

          {/* Preview */}
          {parsedRows.length > 0 && !result && (
            <div>
              <div className="flex items-center justify-between mb-2">
                <span className="text-sm font-medium">Preview ({parsedRows.length} rows)</span>
                <Badge variant="secondary">{fileName}</Badge>
              </div>
              <ScrollArea className="max-h-[250px] rounded-md border">
                <table className="w-full text-xs">
                  <thead className="sticky top-0 bg-muted">
                    <tr className="text-left">
                      <th className="px-3 py-2">#</th>
                      <th className="px-3 py-2">SKU</th>
                      <th className="px-3 py-2">Barcode</th>
                      <th className="px-3 py-2 text-right">New Stock</th>
                    </tr>
                  </thead>
                  <tbody>
                    {parsedRows.slice(0, 100).map((row, idx) => (
                      <tr key={idx} className="border-t border-border/50">
                        <td className="px-3 py-1.5 text-muted-foreground">{idx + 1}</td>
                        <td className="px-3 py-1.5 font-mono">{row.sku || 'ΓÇö'}</td>
                        <td className="px-3 py-1.5 font-mono">{row.barcode || 'ΓÇö'}</td>
                        <td className="px-3 py-1.5 text-right font-amount">{row.stock}</td>
                      </tr>
                    ))}
                    {parsedRows.length > 100 && (
                      <tr className="border-t border-border/50">
                        <td colSpan={4} className="px-3 py-2 text-center text-muted-foreground">
                          ... and {parsedRows.length - 100} more rows
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </ScrollArea>
            </div>
          )}

          {/* Result */}
          {result && (
            <div className="space-y-3">
              <div className="grid grid-cols-3 gap-3">
                <div className="rounded-lg bg-muted/50 p-3 text-center">
                  <div className="text-2xl font-bold">{result.total}</div>
                  <div className="text-xs text-muted-foreground">Total Rows</div>
                </div>
                <div className="rounded-lg bg-green-50 dark:bg-green-900/20 p-3 text-center">
                  <div className="text-2xl font-bold text-green-600">
                    <CheckCircle2 className="h-4 w-4 inline mr-1" />
                    {result.imported}
                  </div>
                  <div className="text-xs text-green-600">Updated</div>
                </div>
                <div className="rounded-lg bg-orange-50 dark:bg-orange-900/20 p-3 text-center">
                  <div className="text-2xl font-bold text-orange-600">
                    <AlertCircle className="h-4 w-4 inline mr-1" />
                    {result.skipped}
                  </div>
                  <div className="text-xs text-orange-600">Skipped</div>
                </div>
              </div>

              {result.errors.length > 0 && (
                <ScrollArea className="max-h-[150px] rounded-md border border-orange-200 bg-orange-50/50 dark:bg-orange-900/10 p-3">
                  <div className="space-y-1">
                    {result.errors.map((err, i) => (
                      <div key={i} className="text-xs text-orange-700 dark:text-orange-400">
                        {err}
                      </div>
                    ))}
                  </div>
                </ScrollArea>
              )}
            </div>
          )}
        </div>

        <DialogFooter>
          {result ? (
            <Button onClick={handleClose}>Done</Button>
          ) : (
            <>
              <Button variant="outline" onClick={handleClose}>
                Cancel
              </Button>
              <Button
                onClick={handleImport}
                disabled={parsedRows.length === 0 || importing}
                className="gap-2"
              >
                {importing ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <Upload className="h-4 w-4" />
                )}
                {importing ? 'Updating...' : `Update ${parsedRows.length} Products`}
              </Button>
            </>
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

// ============================================================================
// KPT Billing - Product Price History Dialog
// Track when prices changed and by how much
// ============================================================================
import { useState, useEffect } from 'react'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '../ui/dialog'
import { Badge } from '../ui/badge'
import { ScrollArea } from '../ui/scroll-area'
import { TrendingUp, TrendingDown, Minus, History } from 'lucide-react'
import { formatCurrency } from '../../lib/utils'

interface PriceHistoryEntry {
  id: number
  productId: number
  productName: string
  fieldName: string
  oldValue: number
  newValue: number
  changedBy: string | null
  createdAt: string
}

interface PriceHistoryDialogProps {
  open: boolean
  onClose: () => void
  productId: number | null
  productName: string
}

const FIELD_LABELS: Record<string, string> = {
  selling_price: 'Selling Price',
  purchase_price: 'Purchase Price',
  wholesale_price: 'Wholesale Price'
}

const FIELD_COLORS: Record<string, string> = {
  selling_price: 'text-primary',
  purchase_price: 'text-orange-600',
  wholesale_price: 'text-purple-600'
}

export function PriceHistoryDialog({
  open,
  onClose,
  productId,
  productName
}: PriceHistoryDialogProps): React.JSX.Element {
  const [entries, setEntries] = useState<PriceHistoryEntry[]>([])
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    if (open && productId) {
      setLoading(true)
      window.api.products
        .getPriceHistory(productId, 100)
        .then((rows) => {
          setEntries(
            rows.map((r: Record<string, unknown>) => ({
              id: r.id as number,
              productId: r.productId as number,
              productName: (r.productName as string) || '',
              fieldName: (r.fieldName as string) || '',
              oldValue: (r.oldValue as number) || 0,
              newValue: (r.newValue as number) || 0,
              changedBy: (r.changedBy as string) || null,
              createdAt: (r.createdAt as string) || ''
            }))
          )
        })
        .catch(() => setEntries([]))
        .finally(() => setLoading(false))
    }
  }, [open, productId])

  const getChangeIndicator = (oldVal: number, newVal: number) => {
    if (newVal > oldVal) {
      return {
        icon: TrendingUp,
        color: 'text-red-500',
        label: `+${formatCurrency(newVal - oldVal)}`
      }
    } else if (newVal < oldVal) {
      return {
        icon: TrendingDown,
        color: 'text-green-500',
        label: `-${formatCurrency(oldVal - newVal)}`
      }
    }
    return { icon: Minus, color: 'text-muted-foreground', label: 'No change' }
  }

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-lg">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <History className="h-5 w-5" />
            Price History
          </DialogTitle>
          <DialogDescription>{productName}</DialogDescription>
        </DialogHeader>

        <div className="py-2">
          {loading && (
            <div className="py-8 text-center text-sm text-muted-foreground">Loading...</div>
          )}

          {!loading && entries.length === 0 && (
            <div className="py-8 text-center text-sm text-muted-foreground">
              No price changes recorded yet for this product.
            </div>
          )}

          {!loading && entries.length > 0 && (
            <ScrollArea className="max-h-[400px]">
              <div className="space-y-2">
                {entries.map((entry) => {
                  const change = getChangeIndicator(entry.oldValue, entry.newValue)
                  const ChangeIcon = change.icon

                  return (
                    <div
                      key={entry.id}
                      className="flex items-center gap-3 rounded-lg border border-border p-3"
                    >
                      <div className={`shrink-0 ${change.color}`}>
                        <ChangeIcon className="h-4 w-4" />
                      </div>

                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <Badge
                            variant="outline"
                            className={`text-[10px] ${FIELD_COLORS[entry.fieldName] || ''}`}
                          >
                            {FIELD_LABELS[entry.fieldName] || entry.fieldName}
                          </Badge>
                          <span className={`text-xs font-medium ${change.color}`}>
                            {change.label}
                          </span>
                        </div>
                        <div className="flex items-center gap-2 mt-1 text-sm">
                          <span className="font-amount text-muted-foreground line-through">
                            {formatCurrency(entry.oldValue)}
                          </span>
                          <span className="text-muted-foreground">ΓåÆ</span>
                          <span className="font-amount font-medium">
                            {formatCurrency(entry.newValue)}
                          </span>
                        </div>
                      </div>

                      <div className="text-xs text-muted-foreground text-right shrink-0">
                        {new Date(entry.createdAt).toLocaleDateString('en-IN', {
                          day: '2-digit',
                          month: 'short',
                          year: 'numeric'
                        })}
                        <br />
                        {new Date(entry.createdAt).toLocaleTimeString('en-IN', {
                          hour: '2-digit',
                          minute: '2-digit'
                        })}
                      </div>
                    </div>
                  )
                })}
              </div>
            </ScrollArea>
          )}
        </div>
      </DialogContent>
    </Dialog>
  )
}

import * as React from 'react'
import { cn } from '@renderer/lib/utils'

function Badge({
  className,
  variant = 'default',
  ...props
}: React.HTMLAttributes<HTMLDivElement> & {
  variant?: 'default' | 'secondary' | 'destructive' | 'outline'
}) {
  return (
    <div
      className={cn(
        'inline-flex items-center rounded-md border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2',
        {
          'border-transparent bg-primary text-primary-foreground shadow hover:bg-primary/80':
