const EMPTY_FORM: CustomerFormData = {
  name: '',
  phone: '',
  email: '',
  address: '',
  city: '',
  gstin: '',
  customerType: 'regular',
  creditLimit: 0
}

const PAYMENT_MODES = [
  { value: 'cash', label: 'Cash' },
  { value: 'upi', label: 'UPI' },
  { value: 'card', label: 'Card' },
  { value: 'cheque', label: 'Cheque' },
  { value: 'bank_transfer', label: 'Bank Transfer' }
] as const

export default function CustomersPage(): React.JSX.Element {
  const [customers, setCustomers] = useState<Customer[]>([])
  const [searchTerm, setSearchTerm] = useState('')
  const [filterType, setFilterType] = useState<string>('all')
  const [loading, setLoading] = useState(false)
  const [showFormDialog, setShowFormDialog] = useState(false)
  const [showDetailDialog, setShowDetailDialog] = useState(false)
  const [showPaymentDialog, setShowPaymentDialog] = useState(false)
  const [editingCustomer, setEditingCustomer] = useState<Customer | null>(null)
  const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null)
  const [customerBills, setCustomerBills] = useState<Bill[]>([])
  const [creditLedger, setCreditLedger] = useState<CreditLedgerEntry[]>([])
  const [creditPayments, setCreditPayments] = useState<CreditPayment[]>([])
  const [formData, setFormData] = useState<CustomerFormData>(EMPTY_FORM)
  const [saving, setSaving] = useState(false)
  const [totalCredit, setTotalCredit] = useState(0)
  const [creditCustomers, setCreditCustomers] = useState<Customer[]>([])

  // Payment form state
  const [paymentAmount, setPaymentAmount] = useState('')
  const [paymentMode, setPaymentMode] = useState<CreditPaymentCreateData['paymentMode']>('cash')
  const [paymentReference, setPaymentReference] = useState('')
  const [paymentNotes, setPaymentNotes] = useState('')
  const [processingPayment, setProcessingPayment] = useState(false)

  const loadCustomers = useCallback(async () => {
    setLoading(true)
    try {
      const [all, credit, total] = await Promise.all([
        window.api.customers.getAll(),
        window.api.customers.getWithCredit(),
        window.api.customers.getTotalCredit()
      ])
      setCustomers(all)
      setCreditCustomers(credit)
      setTotalCredit(total)
    } catch {
      toast.error('Failed to load customers')
    }
    setLoading(false)
  }, [])

  useEffect(() => {
    loadCustomers()
  }, [loadCustomers])

  const filteredCustomers = customers.filter((c) => {
    const matchSearch =
      !searchTerm ||
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.phone.includes(searchTerm) ||
      (c.email && c.email.toLowerCase().includes(searchTerm.toLowerCase()))

    const matchType =
      filterType === 'all' || filterType === 'credit' || c.customerType === filterType
    const matchCredit = filterType !== 'credit' || c.currentBalance > 0

    return matchSearch && matchType && matchCredit
  })

  const openAddDialog = (): void => {
    setEditingCustomer(null)
    setFormData(EMPTY_FORM)
    setShowFormDialog(true)
  }

  const openEditDialog = (customer: Customer): void => {
    setEditingCustomer(customer)
    setFormData({
      name: customer.name,
      phone: customer.phone,
      email: customer.email || '',
      address: customer.address || '',
      city: customer.city || '',
      gstin: customer.gstin || '',
      customerType: customer.customerType || 'regular',
      creditLimit: customer.creditLimit || 0
    })
    setShowFormDialog(true)
  }

  const openDetailDialog = async (customer: Customer): Promise<void> => {
    setSelectedCustomer(customer)
    setShowDetailDialog(true)
    try {
      const [bills, ledger, payments] = await Promise.all([
        window.api.billing.getBillsByCustomer(customer.id, 50),
        window.api.credit.getLedger(customer.id),
        window.api.credit.getByCustomer(customer.id, 50)
      ])
      setCustomerBills(bills)
      setCreditLedger(ledger)
      setCreditPayments(payments)
    } catch {
      setCustomerBills([])
      setCreditLedger([])
      setCreditPayments([])
    }
  }

  const openPaymentDialog = (customer: Customer): void => {
    setSelectedCustomer(customer)
    setPaymentAmount('')
    setPaymentMode('cash')
    setPaymentReference('')
    setPaymentNotes('')
    setShowPaymentDialog(true)
  }

  const handleCollectPayment = async (): Promise<void> => {
    if (!selectedCustomer) return
    const amount = parseFloat(paymentAmount)
    if (!amount || amount <= 0) {
      toast.error('Enter a valid amount')
      return
    }
    if (amount > selectedCustomer.currentBalance) {
      toast.error(
        `Amount Γé╣${amount} exceeds outstanding balance Γé╣${selectedCustomer.currentBalance}`
      )
      return
    }

    setProcessingPayment(true)
    try {
      await window.api.credit.recordPayment({
        customerId: selectedCustomer.id,
        amount,
        paymentMode,
        referenceNo: paymentReference || undefined,
        notes: paymentNotes || undefined
      })

      const balanceAfter = Math.round((selectedCustomer.currentBalance - amount) * 100) / 100

      // Show success with WhatsApp option if phone is available
      if (selectedCustomer.phone && selectedCustomer.phone.length >= 10) {
        toast.success(
          `Γé╣${amount.toLocaleString('en-IN')} collected from ${selectedCustomer.name}`,
          {
            duration: 8000,
            action: {
              label: '≡ƒô▒ WhatsApp Confirmation',
              onClick: () => {
                window.api.whatsapp
                  .sendPaymentConfirmation(
                    selectedCustomer.phone,
                    selectedCustomer.name,
                    amount,
                    balanceAfter,
                    paymentMode,
                    new Date().toISOString().split('T')[0]
                  )
                  .then((res) => {
                    if (!res.success) toast.error(res.error || 'Failed to open WhatsApp')
                  })
              }
            }
          }
        )
      } else {
        toast.success(
          `Γé╣${amount.toLocaleString('en-IN')} collected from ${selectedCustomer.name}. Balance: Γé╣${balanceAfter.toLocaleString('en-IN')}`
        )
      }
      setShowPaymentDialog(false)
      loadCustomers()

      // Refresh detail dialog if open
      if (showDetailDialog && selectedCustomer) {
        const fresh = await window.api.customers.getById(selectedCustomer.id)
        if (fresh) {
          setSelectedCustomer(fresh)
          const [ledger, payments] = await Promise.all([
            window.api.credit.getLedger(fresh.id),
            window.api.credit.getByCustomer(fresh.id, 50)
          ])
          setCreditLedger(ledger)
          setCreditPayments(payments)
        }
      }
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : 'Payment failed'
      toast.error(msg)
    }
    setProcessingPayment(false)
  }

  const handleDeletePayment = async (paymentId: number): Promise<void> => {
    if (!confirm('Delete this payment? The amount will be added back to the customer balance.'))
      return
    try {
      await window.api.credit.deletePayment(paymentId)
      toast.success('Payment deleted and balance restored')
      loadCustomers()
      if (selectedCustomer) {
        const fresh = await window.api.customers.getById(selectedCustomer.id)
        if (fresh) {
          setSelectedCustomer(fresh)
          const [ledger, payments] = await Promise.all([
            window.api.credit.getLedger(fresh.id),
            window.api.credit.getByCustomer(fresh.id, 50)
          ])
          setCreditLedger(ledger)
          setCreditPayments(payments)
        }
      }
    } catch {
      toast.error('Failed to delete payment')
    }
  }

  const handleSave = async (): Promise<void> => {
    if (!formData.name.trim() || !formData.phone.trim()) {
      toast.error('Name and phone are required')
      return
    }

    if (formData.phone.length < 10) {
      toast.error('Phone number must be at least 10 digits')
      return
    }

    setSaving(true)
    try {
      if (editingCustomer) {
        await window.api.customers.update(editingCustomer.id, formData)
        toast.success('Customer updated')
      } else {
        await window.api.customers.create(formData)
        toast.success('Customer added')
      }
      setShowFormDialog(false)
      loadCustomers()
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : 'Save failed'
      toast.error(msg)
    }
    setSaving(false)
  }

  const handleExport = async (): Promise<void> => {
    try {
      const result = await window.api.export.customerReport()
      if (result.success && result.path) {
        toast.success(`Exported to ${result.path}`)
      }
    } catch {
      toast.error('Export failed')
    }
  }

  const handlePayFull = (): void => {
    if (selectedCustomer) {
      setPaymentAmount(String(selectedCustomer.currentBalance))
    }
  }

  return (
    <div className="h-full overflow-auto page-enter">
      <div className="space-y-6 p-6 max-w-[1400px] mx-auto">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Customers</h1>
            <p className="text-sm text-muted-foreground mt-0.5">
              Manage customers, credit &amp; payment collection
            </p>
          </div>
          <div className="flex gap-2">
            <Button variant="outline" onClick={handleExport}>
              <FileDown className="mr-2 h-4 w-4" />
              Export
            </Button>
            <Button onClick={openAddDialog}>
              <Plus className="mr-2 h-4 w-4" />
              Add Customer
            </Button>
          </div>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-3">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Total Customers
              </CardTitle>
              <Users className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{customers.length}</div>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Total Credit Outstanding
              </CardTitle>
              <IndianRupee className="h-4 w-4 text-destructive" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold font-amount text-destructive">
                {formatCurrency(totalCredit)}
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Credit Accounts
              </CardTitle>
              <AlertTriangle className="h-4 w-4 text-orange-500" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{creditCustomers.length}</div>
            </CardContent>
          </Card>
        </div>

        {/* Search & Filters */}
        <div className="flex items-center gap-3">
          <div className="relative flex-1 max-w-md">
