                                    </Badge>
                                  ) : (
                                    formatCurrency(p.balanceAfter)
                                  )}
                                </TableCell>
                                <TableCell className="text-xs max-w-[120px] truncate">
                                  {p.notes || '-'}
                                </TableCell>
                                <TableCell>
                                  <Button
                                    variant="ghost"
                                    size="sm"
                                    className="h-7 w-7 p-0 text-destructive hover:text-destructive"
                                    onClick={() => handleDeletePayment(p.id)}
                                    title="Delete payment"
                                  >
                                    <Trash2 className="h-3.5 w-3.5" />
                                  </Button>
                                </TableCell>
                              </TableRow>
                            ))
                          )}
                        </TableBody>
                      </Table>
                    </CardContent>
                  </Card>
                </TabsContent>

                {/* ============= BILL HISTORY TAB ============= */}
                <TabsContent value="history" className="mt-4">
                  <Card>
                    <CardHeader>
                      <CardTitle className="text-sm flex items-center gap-2">
                        <ShoppingCart className="h-4 w-4" />
                        Recent Purchases ({customerBills.length})
                      </CardTitle>
                    </CardHeader>
                    <CardContent className="p-0">
                      <Table>
                        <TableHeader>
                          <TableRow>
                            <TableHead>Bill No.</TableHead>
                            <TableHead>Date</TableHead>
                            <TableHead>Items</TableHead>
                            <TableHead>Payment</TableHead>
                            <TableHead className="text-right">Credit</TableHead>
                            <TableHead>Status</TableHead>
                            <TableHead className="text-right">Amount</TableHead>
                          </TableRow>
                        </TableHeader>
                        <TableBody>
                          {customerBills.length === 0 ? (
                            <TableRow>
                              <TableCell
                                colSpan={7}
                                className="h-20 text-center text-muted-foreground"
                              >
                                No purchase history
                              </TableCell>
                            </TableRow>
                          ) : (
                            customerBills.map((bill) => (
                              <TableRow key={bill.id}>
                                <TableCell className="font-mono text-xs">
                                  {bill.billNumber || bill.billNo}
                                </TableCell>
                                <TableCell className="text-sm">{formatDate(bill.date)}</TableCell>
                                <TableCell>{bill.totalItems}</TableCell>
                                <TableCell>
                                  <Badge variant="secondary" className="text-[10px]">
                                    {bill.paymentMode?.toUpperCase()}
                                  </Badge>
                                </TableCell>
                                <TableCell className="text-right font-amount text-sm">
                                  {bill.creditAmount > 0 ? (
                                    <span className="text-destructive">
                                      {formatCurrency(bill.creditAmount)}
                                    </span>
                                  ) : (
                                    '-'
                                  )}
                                </TableCell>
                                <TableCell>
                                  <Badge
                                    variant={
                                      bill.status === 'completed'
                                        ? 'default'
                                        : bill.status === 'returned'
                                          ? 'destructive'
                                          : 'outline'
                                    }
                                    className="text-[10px]"
                                  >
                                    {bill.status}
                                  </Badge>
                                </TableCell>
                                <TableCell className="text-right font-amount font-medium">
                                  {formatCurrency(bill.grandTotal)}
                                </TableCell>
                              </TableRow>
                            ))
                          )}
                        </TableBody>
                      </Table>
                    </CardContent>
                  </Card>
                </TabsContent>
              </Tabs>
            )}
          </DialogContent>
        </Dialog>
      </div>
    </div>
  )
}

import { useEffect, useState, useCallback } from 'react'
import { Button } from '../components/ui/button'
import { Input } from '../components/ui/input'
import { Badge } from '../components/ui/badge'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow
} from '../components/ui/table'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger
} from '../components/ui/dropdown-menu'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogDescription
} from '../components/ui/dialog'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue
} from '../components/ui/select'
import { Label } from '../components/ui/label'
import { Separator } from '../components/ui/separator'
import { Textarea } from '../components/ui/textarea'
import {
  Plus,
  Search,
  Upload,
  MoreHorizontal,
  Pencil,
  Trash2,
  ChevronLeft,
  ChevronRight,
  PackagePlus,
  PackageMinus,
  FileDown,
  History,
  Database
} from 'lucide-react'
import { formatCurrency } from '../lib/utils'
import { toast } from 'sonner'
import type { Product, ProductFormData } from '@shared/types'
import { GST_RATES, COMMON_HSN_CODES } from '@shared/constants'
import { BulkStockUpdateDialog } from '../components/products/BulkStockUpdateDialog'
import { PriceHistoryDialog } from '../components/products/PriceHistoryDialog'

const PAGE_SIZE = 25

export default function ProductsPage(): React.JSX.Element {
  const [products, setProducts] = useState<Product[]>([])
  const [total, setTotal] = useState(0)
  const [page, setPage] = useState(1)
  const [search, setSearch] = useState('')
  const [categoryFilter, setCategoryFilter] = useState('')
  const [categories, setCategories] = useState<{ id: number; name: string }[]>([])
  const [loading, setLoading] = useState(false)

  // Dialog states
  const [showForm, setShowForm] = useState(false)
  const [editingProduct, setEditingProduct] = useState<Product | null>(null)
  const [showDelete, setShowDelete] = useState<Product | null>(null)
  const [showStockAdjust, setShowStockAdjust] = useState<Product | null>(null)
  const [adjustType, setAdjustType] = useState<string>('purchase')
  const [adjustQty, setAdjustQty] = useState<number>(0)
  const [adjustNotes, setAdjustNotes] = useState<string>('')
  const [showBulkUpdate, setShowBulkUpdate] = useState(false)
  const [showPriceHistory, setShowPriceHistory] = useState<Product | null>(null)

  const loadProducts = useCallback(async () => {
    setLoading(true)
    try {
      // Find categoryId from name for filter
      let filterCategoryId: number | undefined
      if (categoryFilter) {
        const match = categories.find((c) => c.name === categoryFilter)
        if (match) filterCategoryId = match.id
      }

      const result = await window.api.products.getAll({
        page,
        pageSize: PAGE_SIZE,
        search: search || undefined,
        categoryId: filterCategoryId,
        sortBy: 'name',
        sortOrder: 'asc'
      })
      setProducts(result.data)
      setTotal(result.total)
    } catch (err) {
      toast.error('Failed to load products')
    }
    setLoading(false)
  }, [page, search, categoryFilter, categories])

  const loadCategories = useCallback(async () => {
    try {
      const cats = await window.api.categories.getAll()
      setCategories(cats)
    } catch {
      /* use defaults */
    }
  }, [])

  useEffect(() => {
    loadProducts()
  }, [loadProducts])

  useEffect(() => {
    loadCategories()
  }, [loadCategories])

  // Reset page when filters change
  useEffect(() => {
    setPage(1)
  }, [search, categoryFilter])

  const handleDelete = async (): Promise<void> => {
    if (!showDelete) return
    try {
      await window.api.products.delete(showDelete.id)
      toast.success('Product deleted')
      setShowDelete(null)
      loadProducts()
    } catch (err) {
      toast.error('Failed to delete product')
    }
  }

  const handleImportCsv = async (): Promise<void> => {
    try {
      const result = await window.api.dialog.openFile({
        filters: [{ name: 'CSV Files', extensions: ['csv'] }]
      })
      if (!result) return

      const importResult = await window.api.products.import(result as any)
      toast.success(`Imported ${importResult.imported} products. ${importResult.skipped} skipped.`)
      if (importResult.errors && importResult.errors.length > 0) {
        importResult.errors.slice(0, 5).forEach((e: string) => toast.warning(e))
      }
      loadProducts()
    } catch (err) {
      toast.error('Import failed')
    }
  }

  const handleStockAdjust = async (): Promise<void> => {
    if (!showStockAdjust || adjustQty === 0) {
      toast.error('Quantity must not be zero')
      return
    }
    try {
      const qty = adjustType === 'damage' ? -Math.abs(adjustQty) : Math.abs(adjustQty)
      await window.api.products.adjustStock(showStockAdjust.id, qty, adjustType, adjustNotes)
      toast.success(`Stock ${adjustType === 'damage' ? 'reduced' : 'added'} successfully`)
      setShowStockAdjust(null)
      setAdjustQty(0)
      setAdjustNotes('')
      loadProducts()
    } catch {
      toast.error('Stock adjustment failed')
    }
  }

  const handleExportStock = async (): Promise<void> => {
    try {
      const result = await window.api.export.stockReport()
      if (result.success && result.path) {
        toast.success(`Exported to ${result.path}`)
      }
    } catch {
      toast.error('Export failed')
    }
  }

  const totalPages = Math.ceil(total / PAGE_SIZE)

  return (
    <div className="flex h-full flex-col page-enter">
      {/* Header */}
      <div className="flex items-center justify-between border-b border-border bg-muted/20 px-6 py-4">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Products</h1>
          <p className="text-sm text-muted-foreground">{total} products total</p>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" onClick={handleExportStock} className="gap-2">
            <FileDown className="h-4 w-4" />
            Export Stock
          </Button>
          <Button variant="outline" onClick={() => setShowBulkUpdate(true)} className="gap-2">
            <Database className="h-4 w-4" />
            Bulk Stock Update
          </Button>
          <Button variant="outline" onClick={handleImportCsv} className="gap-2">
            <Upload className="h-4 w-4" />
            Import CSV
          </Button>
          <Button
            onClick={() => {
              setEditingProduct(null)
              setShowForm(true)
            }}
            className="gap-2"
          >
            <Plus className="h-4 w-4" />
            Add Product
          </Button>
        </div>
      </div>

      {/* Filters */}
      <div className="flex items-center gap-3 border-b border-border px-6 py-3">
        <div className="relative flex-1 max-w-sm">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            placeholder="Search by name, SKU, or barcode..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <select
          className="h-10 rounded-md border border-input bg-background px-3 text-sm"
          value={categoryFilter}
          onChange={(e) => setCategoryFilter(e.target.value)}
        >
          <option value="">All Categories</option>
          {categories.map((c) => (
            <option key={c.id} value={c.name}>
              {c.name}
            </option>
          ))}
        </select>
      </div>

      {/* Table */}
      <div className="flex-1 overflow-auto">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead className="w-[50px]">#</TableHead>
              <TableHead>Product Name</TableHead>
              <TableHead>SKU</TableHead>
              <TableHead>Category</TableHead>
              <TableHead className="text-right">Cost</TableHead>
              <TableHead className="text-right">Selling</TableHead>
              <TableHead className="text-right">Stock</TableHead>
              <TableHead className="text-center">GST</TableHead>
              <TableHead className="w-[60px]"></TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {products.length === 0 ? (
              <TableRow>
                <TableCell colSpan={9} className="h-32 text-center text-muted-foreground">
                  {loading ? 'Loading...' : 'No products found'}
                </TableCell>
              </TableRow>
            ) : (
              products.map((product, idx) => (
                <TableRow key={product.id} className="group">
                  <TableCell className="text-muted-foreground">
                    {(page - 1) * PAGE_SIZE + idx + 1}
                  </TableCell>
                  <TableCell>
                    <div className="flex items-center gap-2">
                      <span className="font-medium">{product.name}</span>
                      {product.stock <= 0 && (
                        <Badge variant="destructive" className="text-[10px]">
                          Out
                        </Badge>
                      )}
                      {product.stock > 0 && product.stock <= (product.lowStockThreshold || 5) && (
                        <Badge
                          variant="outline"
                          className="border-yellow-500 text-yellow-600 text-[10px]"
                        >
                          Low
                        </Badge>
                      )}
                    </div>
                  </TableCell>
                  <TableCell className="font-mono text-xs text-muted-foreground">
                    {product.sku}
                  </TableCell>
                  <TableCell>{product.category}</TableCell>
                  <TableCell className="text-right font-amount">
                    {formatCurrency(product.costPrice)}
                  </TableCell>
                  <TableCell className="text-right font-amount font-medium">
                    {formatCurrency(product.sellingPrice)}
                  </TableCell>
                  <TableCell className="text-right font-amount">{product.stock}</TableCell>
                  <TableCell className="text-center">
                    <Badge variant="secondary" className="text-[10px]">
                      {product.gstRate}%
                    </Badge>
                  </TableCell>
                  <TableCell>
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button
                          variant="ghost"
                          size="sm"
                          className="h-8 w-8 p-0 opacity-0 group-hover:opacity-100"
                        >
                          <MoreHorizontal className="h-4 w-4" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuItem
                          onClick={() => {
                            setEditingProduct(product)
                            setShowForm(true)
                          }}
                        >
                          <Pencil className="mr-2 h-4 w-4" />
                          Edit
                        </DropdownMenuItem>
                        <DropdownMenuItem
                          onClick={() => {
                            setShowStockAdjust(product)
                            setAdjustType('purchase')
                            setAdjustQty(0)
                            setAdjustNotes('')
                          }}
                        >
                          <PackagePlus className="mr-2 h-4 w-4" />
                          Adjust Stock
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => setShowPriceHistory(product)}>
                          <History className="mr-2 h-4 w-4" />
                          Price History
                        </DropdownMenuItem>
                        <DropdownMenuSeparator />
                        <DropdownMenuItem
                          onClick={() => setShowDelete(product)}
                          className="text-destructive"
                        >
                          <Trash2 className="mr-2 h-4 w-4" />
                          Delete
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-between border-t border-border px-6 py-3">
          <span className="text-sm text-muted-foreground">
            Page {page} of {totalPages} ({total} items)
          </span>
          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              size="sm"
              disabled={page <= 1}
              onClick={() => setPage((p) => p - 1)}
            >
              <ChevronLeft className="h-4 w-4" />
            </Button>
            <Button
              variant="outline"
              size="sm"
              disabled={page >= totalPages}
              onClick={() => setPage((p) => p + 1)}
            >
              <ChevronRight className="h-4 w-4" />
            </Button>
          </div>
        </div>
      )}

      {/* Add/Edit Product Dialog */}
      <ProductFormDialog
        open={showForm}
        onClose={() => {
          setShowForm(false)
          setEditingProduct(null)
        }}
        product={editingProduct}
        categories={categories}
        onSaved={() => {
          setShowForm(false)
          setEditingProduct(null)
          loadProducts()
        }}
      />

      {/* Delete Confirmation */}
      <Dialog open={!!showDelete} onOpenChange={() => setShowDelete(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Delete Product</DialogTitle>
            <DialogDescription>
              Are you sure you want to delete &quot;{showDelete?.name}&quot;? This action cannot be
              undone.
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowDelete(null)}>
              Cancel
            </Button>
            <Button variant="destructive" onClick={handleDelete}>
              Delete
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Stock Adjustment Dialog */}
      <Dialog open={!!showStockAdjust} onOpenChange={() => setShowStockAdjust(null)}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              {adjustType === 'damage' ? (
                <PackageMinus className="h-5 w-5 text-destructive" />
              ) : (
                <PackagePlus className="h-5 w-5 text-primary" />
              )}
              Adjust Stock
            </DialogTitle>
            <DialogDescription>
              {showStockAdjust?.name} ΓÇö Current stock: {showStockAdjust?.stock ?? 0}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4 py-2">
            <div className="space-y-1.5">
              <Label>Adjustment Type</Label>
              <Select value={adjustType} onValueChange={setAdjustType}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="purchase">Purchase / Restock</SelectItem>
                  <SelectItem value="adjustment">Manual Adjustment</SelectItem>
                  <SelectItem value="damage">Damage / Loss</SelectItem>
                  <SelectItem value="return">Vendor Return</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-1.5">
              <Label>Quantity</Label>
              <Input
                type="number"
                min={1}
                value={adjustQty || ''}
                onChange={(e) => setAdjustQty(parseInt(e.target.value) || 0)}
                placeholder={adjustType === 'damage' ? 'Qty to remove' : 'Qty to add'}
              />
              {adjustType === 'damage' && adjustQty > 0 && (
                <p className="text-xs text-destructive">
                  Stock will be reduced by {adjustQty}. New stock:{' '}
                  {(showStockAdjust?.stock ?? 0) - adjustQty}
                </p>
              )}
              {adjustType !== 'damage' && adjustQty > 0 && (
                <p className="text-xs text-muted-foreground">
                  Stock will increase by {adjustQty}. New stock:{' '}
                  {(showStockAdjust?.stock ?? 0) + adjustQty}
                </p>
              )}
            </div>

            <div className="space-y-1.5">
              <Label>Notes (optional)</Label>
              <Textarea
                value={adjustNotes}
                onChange={(e) => setAdjustNotes(e.target.value)}
                placeholder="e.g. Purchase invoice #123, Damaged in transit..."
                rows={2}
              />
            </div>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setShowStockAdjust(null)}>
              Cancel
            </Button>
            <Button onClick={handleStockAdjust} disabled={adjustQty === 0}>
              {adjustType === 'damage' ? 'Remove Stock' : 'Add Stock'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Bulk Stock Update Dialog */}
      <BulkStockUpdateDialog
        open={showBulkUpdate}
        onClose={() => setShowBulkUpdate(false)}
        onComplete={() => {
          setShowBulkUpdate(false)
          loadProducts()
        }}
      />

      {/* Price History Dialog */}
      {showPriceHistory && (
        <PriceHistoryDialog
          open={!!showPriceHistory}
          productId={showPriceHistory.id}
          productName={showPriceHistory.name}
          onClose={() => setShowPriceHistory(null)}
        />
      )}
    </div>
  )
}

// ---- Product Form Dialog ----

function ProductFormDialog({
  open,
  onClose,
  product,
  categories,
  onSaved
}: {
  open: boolean
  onClose: () => void
  product: Product | null
  categories: { id: number; name: string }[]
  onSaved: () => void
}): React.JSX.Element {
  const [form, setForm] = useState<ProductFormData>({
    name: '',
    category: '',
    costPrice: 0,
    sellingPrice: 0,
    gstRate: 5,
    hsnCode: '',
    stock: 0,
    unit: 'pcs',
    lowStockThreshold: 5,
    barcode: '',
    description: ''
  })
  const [saving, setSaving] = useState(false)

  useEffect(() => {
    if (product) {
      setForm({
        name: product.name,
        category: product.category || undefined,
        costPrice: product.costPrice,
        sellingPrice: product.sellingPrice,
        gstRate: product.gstRate,
        hsnCode: product.hsnCode || '',
        stock: product.stock,
        unit: product.unit || 'pcs',
        lowStockThreshold: product.lowStockThreshold || 5,
        barcode: product.barcode || '',
        description: product.description || ''
      })
    } else {
      setForm({
        name: '',
        category: categories[0]?.name || '',
        costPrice: 0,
        sellingPrice: 0,
        gstRate: 5,
        hsnCode: '',
        stock: 0,
        unit: 'pcs',
        lowStockThreshold: 5,
        barcode: '',
        description: ''
      })
    }
  }, [product, open, categories])

  const handleSave = async (): Promise<void> => {
    if (!form.name.trim()) {
      toast.error('Product name is required')
      return
    }
    if (form.sellingPrice <= 0) {
      toast.error('Selling price must be greater than 0')
      return
    }

    setSaving(true)
    try {
      if (product) {
        await window.api.products.update(product.id, form)
        toast.success('Product updated')
      } else {
        await window.api.products.create(form)
        toast.success('Product created')
      }
      onSaved()
    } catch (err) {
      toast.error('Failed to save product')
    }
    setSaving(false)
  }

  const updateField = <K extends keyof ProductFormData>(
    key: K,
    value: ProductFormData[K]
  ): void => {
    setForm((prev) => ({ ...prev, [key]: value }))
  }

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl">
        <DialogHeader>
          <DialogTitle>{product ? 'Edit Product' : 'Add New Product'}</DialogTitle>
        </DialogHeader>
        <div className="grid grid-cols-2 gap-4 py-4">
          {/* Name */}
          <div className="col-span-2 space-y-2">
            <Label>
              Product Name <span className="text-destructive">*</span>
            </Label>
            <Input
              value={form.name}
              onChange={(e) => updateField('name', e.target.value)}
              placeholder="e.g. Kanchipuram Silk Saree - Red"
              autoFocus
            />
          </div>

          {/* Category */}
          <div className="space-y-2">
            <Label>Category</Label>
            <select
              className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
              value={form.category}
              onChange={(e) => updateField('category', e.target.value)}
            >
              <option value="">Select category</option>
              {categories.map((c) => (
                <option key={c.id} value={c.name}>
                  {c.name}
                </option>
              ))}
            </select>
          </div>

          {/* HSN Code */}
          <div className="space-y-2">
            <Label>HSN Code</Label>
            <select
              className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
              value={form.hsnCode}
              onChange={(e) => updateField('hsnCode', e.target.value)}
            >
              <option value="">Select HSN</option>
              {COMMON_HSN_CODES.map((h) => (
                <option key={h.code} value={h.code}>
                  {h.code} - {h.description}
                </option>
              ))}
            </select>
          </div>

          <Separator className="col-span-2" />

          {/* Cost Price */}
          <div className="space-y-2">
            <Label>Cost Price (Γé╣)</Label>
            <Input
              type="number"
              min={0}
              step={0.01}
              value={form.costPrice || ''}
              onChange={(e) => updateField('costPrice', parseFloat(e.target.value) || 0)}
            />
          </div>

          {/* Selling Price */}
          <div className="space-y-2">
            <Label>
              Selling Price (Γé╣) <span className="text-destructive">*</span>
            </Label>
            <Input
              type="number"
              min={0}
              step={0.01}
              value={form.sellingPrice || ''}
              onChange={(e) => updateField('sellingPrice', parseFloat(e.target.value) || 0)}
            />
          </div>

          {/* GST Rate */}
          <div className="space-y-2">
            <Label>GST Rate (%)</Label>
            <select
              className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
              value={form.gstRate}
              onChange={(e) => updateField('gstRate', parseInt(e.target.value))}
            >
              {GST_RATES.map((r) => (
                <option key={r} value={r}>
                  {r}%
                </option>
              ))}
            </select>
          </div>

          {/* Unit */}
          <div className="space-y-2">
            <Label>Unit</Label>
            <select
              className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
              value={form.unit}
              onChange={(e) => updateField('unit', e.target.value)}
            >
              <option value="pcs">Pieces</option>
              <option value="mtr">Meters</option>
              <option value="kg">Kilograms</option>
              <option value="set">Set</option>
              <option value="box">Box</option>
            </select>
          </div>

          <Separator className="col-span-2" />

          {/* Stock */}
          <div className="space-y-2">
            <Label>Opening Stock</Label>
            <Input
              type="number"
              min={0}
              value={form.stock || ''}
              onChange={(e) => updateField('stock', parseInt(e.target.value) || 0)}
            />
          </div>

          {/* Low Stock Threshold */}
          <div className="space-y-2">
            <Label>Low Stock Alert</Label>
            <Input
              type="number"
              min={0}
              value={form.lowStockThreshold || ''}
              onChange={(e) => updateField('lowStockThreshold', parseInt(e.target.value) || 0)}
            />
          </div>

          {/* Barcode */}
          <div className="space-y-2">
            <Label>Barcode</Label>
            <Input
              value={form.barcode || ''}
              onChange={(e) => updateField('barcode', e.target.value)}
              placeholder="Scan or enter barcode"
            />
          </div>

          {/* Description */}
          <div className="space-y-2">
            <Label>Description</Label>
            <Input
              value={form.description || ''}
              onChange={(e) => updateField('description', e.target.value)}
              placeholder="Optional notes"
            />
          </div>
        </div>

        {/* Margin preview */}
        {form.costPrice > 0 && form.sellingPrice > 0 && (
          <div className="rounded-lg bg-muted/50 p-3 text-sm">
            <span className="text-muted-foreground">Margin: </span>
            <span className="font-medium">
              {formatCurrency(form.sellingPrice - form.costPrice)}
            </span>
            <span className="text-muted-foreground">
              {' '}
              ({(((form.sellingPrice - form.costPrice) / form.costPrice) * 100).toFixed(1)}%)
            </span>
          </div>
        )}

        <DialogFooter>
          <Button variant="outline" onClick={onClose}>
            Cancel
          </Button>
          <Button onClick={handleSave} disabled={saving}>
            {saving ? 'Saving...' : product ? 'Update Product' : 'Add Product'}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

// ============================================================================
// KPT Billing - Purchases Page (Stock-In / Bulk Purchasing)
// Record purchases from suppliers in Surat, Bengaluru, etc.
// Full barcode scanner support for quick product entry.
// ============================================================================
import { useEffect, useRef, useState, useCallback } from 'react'
import { Button } from '../components/ui/button'
import { Input } from '../components/ui/input'
import { Label } from '../components/ui/label'
import { Badge } from '../components/ui/badge'
import { Separator } from '../components/ui/separator'
import { ScrollArea } from '../components/ui/scroll-area'
import { Textarea } from '../components/ui/textarea'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogDescription
} from '../components/ui/dialog'
import {
  Search,
  Trash2,
  Plus,
  Package,
  Truck,
  MapPin,
  ScanBarcode,
  Save,
  Eye,
  FileText
} from 'lucide-react'
import { formatCurrency } from '../lib/utils'
import { toast } from 'sonner'
import type { Product, Supplier, PurchaseItem, PurchaseCreateData, Purchase } from '@shared/types'

// Barcode scanner detection - scanners type fast then press Enter
const BARCODE_THRESHOLD_MS = 80
const BARCODE_MIN_LENGTH = 4

interface PurchaseLineItem extends PurchaseItem {
  _uid: string
}

function uid(): string {
  return Math.random().toString(36).substring(2, 10)
}

export default function PurchasesPage(): React.JSX.Element {
  // ---- State ----
  const [tab, setTab] = useState<'new' | 'history'>('new')

  // New Purchase form state
  const [items, setItems] = useState<PurchaseLineItem[]>([])
  const [supplierId, setSupplierId] = useState<number | null>(null)
  const [supplierName, setSupplierName] = useState('')
  const [city, setCity] = useState('')
  const [invoiceNo, setInvoiceNo] = useState('')
  const [invoiceDate, setInvoiceDate] = useState(new Date().toISOString().split('T')[0])
  const [paymentMode, setPaymentMode] = useState('cash')
  const [paymentStatus, setPaymentStatus] = useState('paid')
  const [amountPaid, setAmountPaid] = useState(0)
  const [notes, setNotes] = useState('')

  // Search state
  const [searchQuery, setSearchQuery] = useState('')
  const [searchResults, setSearchResults] = useState<Product[]>([])
  const [showResults, setShowResults] = useState(false)
  const [selectedResultIdx, setSelectedResultIdx] = useState(0)

  // Supplier search
  const [supplierSearch, setSupplierSearch] = useState('')
  const [supplierResults, setSupplierResults] = useState<Supplier[]>([])
  const [showSupplierResults, setShowSupplierResults] = useState(false)
  const [showNewSupplier, setShowNewSupplier] = useState(false)

  // History
  const [purchases, setPurchases] = useState<Purchase[]>([])
  const [viewPurchase, setViewPurchase] = useState<Purchase | null>(null)

  // Cities
  const [cities, setCities] = useState<string[]>([])
  const [showCityDropdown, setShowCityDropdown] = useState(false)

  // Barcode scanner detection
  const scanBufferRef = useRef('')
  const scanTimerRef = useRef<NodeJS.Timeout | null>(null)
  const lastKeypressRef = useRef(0)
  const searchRef = useRef<HTMLInputElement>(null)

  // Load cities + recent purchases on mount
  useEffect(() => {
    loadCities()
    if (tab === 'history') loadPurchases()
  }, [tab])

  const loadCities = async (): Promise<void> => {
    try {
      const c = await window.api.suppliers.getCities()
      setCities(c)
    } catch {
      /* ignore */
    }
  }

  const loadPurchases = async (): Promise<void> => {
    try {
      const result = await window.api.purchases.getAll({ pageSize: 100 })
      setPurchases(result.data)
    } catch {
      /* ignore */
    }
  }

  // ---- Barcode Scanner Detection (global keydown) ----
  useEffect(() => {
    const handler = (e: KeyboardEvent): void => {
      // Don't capture if typing in an input/textarea (except the search bar)
      const target = e.target as HTMLElement
      const isSearchBar = target === searchRef.current
      if (!isSearchBar && (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA')) {
        return
      }

      const now = Date.now()

      // If the key is Enter and we have a buffer, process it as barcode
      if (e.key === 'Enter' && scanBufferRef.current.length >= BARCODE_MIN_LENGTH) {
        e.preventDefault()
        const barcode = scanBufferRef.current.trim()
        scanBufferRef.current = ''
        handleBarcodeScan(barcode)
        return
      }

      // Single printable character
      if (e.key.length === 1 && !e.ctrlKey && !e.altKey && !e.metaKey) {
        const timeSinceLastKey = now - lastKeypressRef.current
        lastKeypressRef.current = now

        if (timeSinceLastKey > BARCODE_THRESHOLD_MS * 3) {
          // Too slow, reset buffer (probably manual typing)
          scanBufferRef.current = ''
        }

        scanBufferRef.current += e.key

        // Clear any pending timer
        if (scanTimerRef.current) clearTimeout(scanTimerRef.current)

        // After 300ms of no input, clear buffer
        scanTimerRef.current = setTimeout(() => {
          scanBufferRef.current = ''
        }, 300)
      }
    }

    window.addEventListener('keydown', handler, true)
    return () => window.removeEventListener('keydown', handler, true)
  }, [items])

  const handleBarcodeScan = async (barcode: string): Promise<void> => {
    try {
      const product = await window.api.products.getByBarcode(barcode)
      if (product) {
        addProductToItems(product)
        toast.success(`Scanned: ${product.name}`)
      } else {
        toast.warning(`No product found for barcode: ${barcode}`)
        // Focus search bar and put barcode there
        setSearchQuery(barcode)
        searchRef.current?.focus()
      }
    } catch {
      toast.error('Barcode scan failed')
    }
  }

  // ---- Product Search ----
  const handleSearch = useCallback(async (query: string): Promise<void> => {
    setSearchQuery(query)
    if (query.length < 1) {
      setSearchResults([])
      setShowResults(false)
      return
    }
    try {
      const results = await window.api.products.search(query)
      setSearchResults(results.slice(0, 10))
      setShowResults(true)
      setSelectedResultIdx(0)
    } catch {
      setSearchResults([])
    }
  }, [])

  const handleSearchKeyDown = (e: React.KeyboardEvent): void => {
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      setSelectedResultIdx((i) => Math.min(i + 1, searchResults.length - 1))
    } else if (e.key === 'ArrowUp') {
      e.preventDefault()
      setSelectedResultIdx((i) => Math.max(i - 1, 0))
    } else if (e.key === 'Enter' && searchResults.length > 0) {
      e.preventDefault()
      addProductToItems(searchResults[selectedResultIdx])
    }
  }

  const addProductToItems = (product: Product): void => {
    // Check if already in items
    const existing = items.find((i) => i.productId === product.id)
    if (existing) {
      setItems(items.map((i) => (i._uid === existing._uid ? { ...i, qty: i.qty + 1 } : i)))
    } else {
      const newItem: PurchaseLineItem = {
        _uid: uid(),
        productId: product.id,
        productName: product.name,
        barcode: product.barcode,
        hsnCode: product.hsnCode,
        qty: 1,
        purchaseRate: product.costPrice || 0,
        sellingRate: product.sellingPrice || 0,
        mrp: product.sellingPrice || 0,
        gstRate: product.gstRate || 0,
        gstAmount: 0,
        amount: 0
      }
      // Compute amounts
      const updated = recalcItem(newItem)
      setItems([...items, updated])
    }
    setSearchQuery('')
    setSearchResults([])
    setShowResults(false)
    searchRef.current?.focus()
  }

  const recalcItem = (item: PurchaseLineItem): PurchaseLineItem => {
    const lineTotal = item.purchaseRate * item.qty
    const gstAmount = (lineTotal * item.gstRate) / 100
    return { ...item, gstAmount, amount: lineTotal + gstAmount }
  }

  const updateItem = (uid: string, field: string, value: number): void => {
    setItems(
      items.map((item) => {
        if (item._uid !== uid) return item
        const updated = { ...item, [field]: value }
        return recalcItem(updated)
      })
    )
  }

  const removeItem = (uid: string): void => {
    setItems(items.filter((i) => i._uid !== uid))
  }

  // ---- Supplier Search ----
  const handleSupplierSearch = useCallback(async (query: string): Promise<void> => {
    setSupplierSearch(query)
    if (query.length < 1) {
      setSupplierResults([])
      setShowSupplierResults(false)
      return
    }
    try {
      const results = await window.api.suppliers.search(query)
      setSupplierResults(results)
      setShowSupplierResults(true)
    } catch {
      setSupplierResults([])
    }
  }, [])

  const selectSupplier = (supplier: Supplier): void => {
    setSupplierId(supplier.id)
    setSupplierName(supplier.name)
    setCity(supplier.city || '')
    setSupplierSearch(supplier.name)
    setShowSupplierResults(false)
  }

  // ---- Totals ----
  const subtotal = items.reduce((s, i) => s + i.purchaseRate * i.qty, 0)
  const totalGst = items.reduce((s, i) => s + i.gstAmount, 0)
  const grandTotal = subtotal + totalGst
  const totalQty = items.reduce((s, i) => s + i.qty, 0)

  // ---- Save Purchase ----
  const handleSave = async (): Promise<void> => {
    if (items.length === 0) {
      toast.error('Add at least one item')
      return
    }

    try {
      const data: PurchaseCreateData = {
        supplierId: supplierId ?? undefined,
        supplierName: supplierName || undefined,
        city: city || undefined,
        invoiceNo: invoiceNo || undefined,
        invoiceDate: invoiceDate || undefined,
        paymentMode,
        paymentStatus,
        amountPaid: paymentStatus === 'paid' ? grandTotal : amountPaid,
        notes: notes || undefined,
        items: items.map((i) => ({
          productId: i.productId,
          productName: i.productName,
          barcode: i.barcode,
          hsnCode: i.hsnCode,
          qty: i.qty,
          purchaseRate: i.purchaseRate,
          sellingRate: i.sellingRate,
          mrp: i.mrp,
          gstRate: i.gstRate,
          gstAmount: i.gstAmount,
          amount: i.amount
        }))
      }

      const result = await window.api.purchases.create(data)
      toast.success(`Purchase ${result.purchaseNo} saved! Stock updated for ${items.length} items.`)

      // Reset form
      setItems([])
      setSupplierId(null)
      setSupplierName('')
      setCity('')
      setInvoiceNo('')
      setInvoiceDate(new Date().toISOString().split('T')[0])
      setPaymentMode('cash')
      setPaymentStatus('paid')
      setAmountPaid(0)
      setNotes('')
    } catch (err) {
      toast.error(`Failed to save: ${err instanceof Error ? err.message : String(err)}`)
    }
  }

  // ---- Add manual (non-product) item ----
  const addManualItem = (): void => {
    const newItem: PurchaseLineItem = {
      _uid: uid(),
      productId: null,
      productName: '',
      barcode: null,
      hsnCode: null,
      qty: 1,
      purchaseRate: 0,
      sellingRate: 0,
      mrp: 0,
      gstRate: 5,
      gstAmount: 0,
      amount: 0
    }
    setItems([...items, newItem])
  }

  // ---- Render ----
  return (
    <div className="flex h-full flex-col page-enter">
      {/* Header */}
      <div className="flex items-center justify-between border-b border-border bg-muted/20 px-6 py-3">
        <div className="flex items-center gap-3">
          <Truck className="h-5 w-5 text-primary" />
          <h1 className="text-lg font-bold tracking-tight">Purchases / Stock-In</h1>
        </div>
        <div className="flex items-center gap-2">
          <Button
            variant={tab === 'new' ? 'default' : 'outline'}
            size="sm"
            onClick={() => setTab('new')}
          >
            <Plus className="mr-1 h-4 w-4" />
            New Purchase
          </Button>
          <Button
            variant={tab === 'history' ? 'default' : 'outline'}
            size="sm"
            onClick={() => setTab('history')}
          >
            <FileText className="mr-1 h-4 w-4" />
            History
          </Button>
        </div>
      </div>

      {tab === 'new' ? (
        <div className="flex flex-1 overflow-hidden">
          {/* Left: Items */}
          <div className="flex flex-1 flex-col border-r border-border">
            {/* Search Bar with barcode indicator */}
            <div className="relative border-b border-border p-3">
              <div className="flex items-center gap-2">
                <div className="relative flex-1">
                  <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                  <Input
                    ref={searchRef}
                    value={searchQuery}
                    onChange={(e) => handleSearch(e.target.value)}
                    onKeyDown={handleSearchKeyDown}
                    onFocus={() => searchResults.length > 0 && setShowResults(true)}
                    onBlur={() => setTimeout(() => setShowResults(false), 200)}
                    placeholder="Search product or scan barcode..."
                    className="pl-9 text-base"
                  />
                </div>
                <Badge variant="outline" className="gap-1 text-xs text-muted-foreground">
                  <ScanBarcode className="h-3 w-3" />
                  Scanner Ready
                </Badge>
                <Button variant="outline" size="sm" onClick={addManualItem}>
                  <Plus className="mr-1 h-3 w-3" />
                  Manual
                </Button>
              </div>

              {/* Search Dropdown */}
              {showResults && searchResults.length > 0 && (
                <div className="absolute left-3 right-3 top-full z-50 mt-1 max-h-72 overflow-auto rounded-lg border border-border bg-popover shadow-lg">
                  {searchResults.map((product, idx) => (
                    <button
                      key={product.id}
                      className={`flex w-full items-center justify-between px-4 py-2 text-left text-sm transition-colors ${
                        idx === selectedResultIdx ? 'bg-accent' : 'hover:bg-accent/50'
                      }`}
                      onMouseDown={(e) => {
                        e.preventDefault()
                        addProductToItems(product)
                      }}
                      onMouseEnter={() => setSelectedResultIdx(idx)}
                    >
                      <div>
                        <div className="font-medium">{product.name}</div>
                        <div className="text-xs text-muted-foreground">
                          {product.sku}
                          {product.barcode && ` ΓÇó ${product.barcode}`} ΓÇó Stock: {product.stock}
                        </div>
                      </div>
                      <div className="text-right text-xs">
                        <div>Cost: {formatCurrency(product.costPrice)}</div>
                        <div className="text-muted-foreground">
                          Sell: {formatCurrency(product.sellingPrice)}
                        </div>
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>

            {/* Items Table */}
            <div className="flex-1 overflow-auto">
              {items.length === 0 ? (
                <div className="flex h-full flex-col items-center justify-center text-muted-foreground">
                  <Package className="mb-3 h-12 w-12 opacity-20" />
                  <p className="text-lg font-medium">No items added</p>
                  <p className="text-sm">Search products, scan barcodes, or add manually</p>
                </div>
              ) : (
                <table className="w-full text-sm">
                  <thead className="sticky top-0 bg-muted/80 backdrop-blur-sm">
                    <tr className="text-left text-xs font-medium uppercase text-muted-foreground">
                      <th className="w-[30px] px-3 py-2">#</th>
                      <th className="px-2 py-2">Product</th>
                      <th className="w-[80px] px-2 py-2 text-right">Qty</th>
                      <th className="w-[100px] px-2 py-2 text-right">Purchase Γé╣</th>
                      <th className="w-[100px] px-2 py-2 text-right">Selling Γé╣</th>
                      <th className="w-[60px] px-2 py-2 text-right">GST%</th>
                      <th className="w-[80px] px-2 py-2 text-right">GST Γé╣</th>
                      <th className="w-[100px] px-2 py-2 text-right">Amount</th>
                      <th className="w-[40px] px-2 py-2" />
                    </tr>
                  </thead>
                  <tbody>
                    {items.map((item, idx) => (
                      <tr key={item._uid} className="border-b border-border/50">
                        <td className="px-3 py-1.5 text-muted-foreground">{idx + 1}</td>
                        <td className="px-2 py-1.5">
                          {item.productId ? (
                            <div>
                              <div className="font-medium">{item.productName}</div>
                              {item.barcode && (
                                <div className="text-xs text-muted-foreground">{item.barcode}</div>
                              )}
                            </div>
                          ) : (
                            <Input
                              value={item.productName}
                              onChange={(e) =>
                                setItems(
                                  items.map((i) =>
                                    i._uid === item._uid ? { ...i, productName: e.target.value } : i
                                  )
                                )
                              }
                              placeholder="Product name"
                              className="h-7 text-sm"
                            />
                          )}
                        </td>
                        <td className="px-2 py-1.5">
                          <Input
                            type="number"
                            min={1}
                            value={item.qty}
                            onChange={(e) =>
                              updateItem(item._uid, 'qty', parseInt(e.target.value) || 1)
                            }
                            className="h-7 w-full text-right text-sm"
                          />
                        </td>
                        <td className="px-2 py-1.5">
                          <Input
                            type="number"
                            step="0.01"
                            value={item.purchaseRate}
                            onChange={(e) =>
                              updateItem(item._uid, 'purchaseRate', parseFloat(e.target.value) || 0)
                            }
                            className="h-7 w-full text-right text-sm"
                          />
                        </td>
                        <td className="px-2 py-1.5">
                          <Input
                            type="number"
                            step="0.01"
                            value={item.sellingRate}
                            onChange={(e) =>
                              updateItem(item._uid, 'sellingRate', parseFloat(e.target.value) || 0)
                            }
                            className="h-7 w-full text-right text-sm"
                          />
                        </td>
                        <td className="px-2 py-1.5">
                          <Input
                            type="number"
                            step="0.5"
                            value={item.gstRate}
                            onChange={(e) =>
                              updateItem(item._uid, 'gstRate', parseFloat(e.target.value) || 0)
                            }
                            className="h-7 w-full text-right text-sm"
                          />
                        </td>
                        <td className="px-2 py-1.5 text-right text-muted-foreground">
                          {formatCurrency(item.gstAmount)}
                        </td>
                        <td className="px-2 py-1.5 text-right font-medium">
                          {formatCurrency(item.amount)}
                        </td>
                        <td className="px-2 py-1.5">
                          <Button
                            variant="ghost"
                            size="icon"
                            className="h-6 w-6 text-destructive"
                            onClick={() => removeItem(item._uid)}
                          >
                            <Trash2 className="h-3 w-3" />
                          </Button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>

            {/* Bottom Summary Bar */}
            {items.length > 0 && (
              <div className="flex items-center justify-between border-t border-border bg-muted/30 px-4 py-2 text-sm">
                <span>
                  {items.length} items ΓÇó {totalQty} qty
                </span>
                <div className="flex items-center gap-4">
                  <span>
                    Subtotal: <b>{formatCurrency(subtotal)}</b>
                  </span>
                  <span>
                    GST: <b>{formatCurrency(totalGst)}</b>
                  </span>
                  <span className="text-base font-bold text-primary">
                    Total: {formatCurrency(grandTotal)}
                  </span>
                </div>
              </div>
            )}
          </div>

          {/* Right: Supplier & Purchase Details */}
          <div className="flex w-[320px] min-w-[280px] flex-col bg-card">
            <ScrollArea className="flex-1">
              <div className="space-y-4 p-4">
                {/* Supplier */}
                <div>
                  <Label className="text-xs font-semibold uppercase text-muted-foreground">
                    Supplier
                  </Label>
                  <div className="relative mt-1">
                    <Input
                      value={supplierSearch}
                      onChange={(e) => handleSupplierSearch(e.target.value)}
                      onFocus={() => supplierResults.length > 0 && setShowSupplierResults(true)}
                      onBlur={() => setTimeout(() => setShowSupplierResults(false), 200)}
                      placeholder="Search supplier..."
                      className="text-sm"
                    />
                    {showSupplierResults && supplierResults.length > 0 && (
                      <div className="absolute left-0 right-0 top-full z-50 mt-1 max-h-48 overflow-auto rounded-lg border bg-popover shadow-lg">
                        {supplierResults.map((s) => (
                          <button
                            key={s.id}
                            className="flex w-full items-center justify-between px-3 py-2 text-left text-sm hover:bg-accent"
                            onMouseDown={(e) => {
                              e.preventDefault()
                              selectSupplier(s)
                            }}
                          >
                            <div>
                              <div className="font-medium">{s.name}</div>
                              {s.city && (
