// ---- New Supplier Dialog ----
function NewSupplierDialog({
  open,
  defaultCity,
  onClose,
  onCreated
}: {
  open: boolean
  defaultCity: string
  onClose: () => void
  onCreated: (supplier: Supplier) => void
}): React.JSX.Element {
  const [name, setName] = useState('')
  const [phone, setPhone] = useState('')
  const [dialogCity, setDialogCity] = useState(defaultCity)
  const [address, setAddress] = useState('')
  const [gstin, setGstin] = useState('')

  useEffect(() => {
    if (open) setDialogCity(defaultCity)
  }, [open, defaultCity])

  const handleCreate = async (): Promise<void> => {
    if (!name.trim()) {
      toast.error('Supplier name is required')
      return
    }
    try {
      const supplier = await window.api.suppliers.create({
        name: name.trim(),
        phone: phone || undefined,
        city: dialogCity || undefined,
        address: address || undefined,
        gstin: gstin || undefined
      })
      onCreated(supplier)
      // Reset
      setName('')
      setPhone('')
      setDialogCity('')
      setAddress('')
      setGstin('')
    } catch (err) {
      toast.error(`Failed: ${err instanceof Error ? err.message : String(err)}`)
    }
  }

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Add New Supplier</DialogTitle>
          <DialogDescription>
            Add a supplier from any city (Surat, Bengaluru, etc.)
          </DialogDescription>
        </DialogHeader>
        <div className="space-y-3">
          <div>
            <Label>Name *</Label>
            <Input
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Supplier name"
            />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <Label>Phone</Label>
              <Input value={phone} onChange={(e) => setPhone(e.target.value)} placeholder="Phone" />
            </div>
            <div>
              <Label>City</Label>
              <Input
                value={dialogCity}
                onChange={(e) => setDialogCity(e.target.value)}
                placeholder="Surat, Bengaluru..."
              />
            </div>
          </div>
          <div>
            <Label>Address</Label>
            <Input
              value={address}
              onChange={(e) => setAddress(e.target.value)}
              placeholder="Full address"
            />
          </div>
          <div>
            <Label>GSTIN</Label>
            <Input
              value={gstin}
              onChange={(e) => setGstin(e.target.value)}
              placeholder="GSTIN number"
            />
          </div>
        </div>
        <DialogFooter>
          <Button variant="outline" onClick={onClose}>
            Cancel
          </Button>
          <Button onClick={handleCreate}>Create Supplier</Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

