  netMarginPercent: number
  otherInfo: {
    totalDiscount: number
    totalCreditSales: number
    totalCreditCollected: number
    avgBillValue: number
  }
}

function getMonthName(ym: string): string {
  const [, m] = ym.split('-')
  return MONTH_NAMES[parseInt(m, 10) - 1] || m
}

