                <Badge
                  variant={selectedBill?.status === 'completed' ? 'default' : 'destructive'}
                  className="text-[10px]"
                >
                  {selectedBill?.status}
                </Badge>
              </DialogDescription>
            </DialogHeader>

            {selectedBill && (
              <div className="space-y-4">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Item</TableHead>
                      <TableHead className="text-right">Rate</TableHead>
                      <TableHead className="text-right">Qty</TableHead>
                      <TableHead className="text-right">Disc</TableHead>
                      <TableHead className="text-right">GST</TableHead>
                      <TableHead className="text-right">Total</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {(selectedBill.items || []).map((item: BillItem, idx: number) => {
                      const returnedQty = (item as any).returnedQty || 0
                      const isFullyReturned = returnedQty >= item.quantity
                      return (
                        <TableRow
                          key={idx}
                          className={isFullyReturned ? 'opacity-40 line-through' : ''}
                        >
                          <TableCell className="text-sm">
                            {item.productName}
                            {returnedQty > 0 && returnedQty < item.quantity && (
                              <span className="text-[10px] text-orange-600 font-medium ml-1">
                                ({returnedQty} returned)
                              </span>
                            )}
